// AUTO-POPULATE EXCLUSIONS & ASSUMPTIONS
// Runs automatically after AI analysis completes.
// Fills based on: (1) selected disciplines, (2) by_others items
// from AI pathway analysis, (3) AI-detected annotations (FBO/NIC/OFCI)
// ═══════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════
// AUTO-POPULATE RATE LIBRARY — Silently save BOM prices after analysis
// New items are saved to D1; existing rates are NOT overwritten.
// This builds a growing knowledge base of real project pricing.
// ═══════════════════════════════════════════════════════════════
async function _autoPopulateRateLibrary() {
  try {
    if (!state.aiAnalysis) return;
    const bom = typeof SmartPlansExport !== 'undefined' && SmartPlansExport._extractBOMFromAnalysis
      ? SmartPlansExport._extractBOMFromAnalysis(state.aiAnalysis)
      : null;
    if (!bom?.categories || bom.categories.length === 0) return;

    // Fetch existing rates to avoid duplicates
    const headers = {};
    if (typeof _sessionToken !== 'undefined' && _sessionToken) headers['X-Session-Token'] = _sessionToken;
    if (typeof _appToken !== 'undefined' && _appToken) headers['X-App-Token'] = _appToken;
    headers['Content-Type'] = 'application/json';

    let existingNames = new Set();
    try {
      const resp = await fetch('/api/rate-library', { headers });
      if (resp.ok) {
        const data = await resp.json();
        existingNames = new Set((data.rates || []).map(r => (r.item_name || '').toLowerCase()));
      }
    } catch (e) { /* proceed without dedup — may cause harmless duplicate attempts */ }

    let saved = 0;
    let skipped = 0;
    const projectLabel = state.projectName || 'Untitled';

    for (const cat of bom.categories) {
      for (const item of (cat.items || [])) {
        const itemName = (item.item || item.name || '').trim();
        const unitCost = item.unit_cost || item.unitCost || 0;

        // Skip empty, unnamed, or zero-cost items
        if (!itemName || itemName.length < 3 || unitCost <= 0) { skipped++; continue; }
        // Skip consumables and waste factor items
        if (/consumable|waste|spare|attic stock|small tools/i.test(itemName)) { skipped++; continue; }
        // Skip if already in library
        if (existingNames.has(itemName.toLowerCase())) { skipped++; continue; }

        try {
          await fetch('/api/rate-library', {
            method: 'POST',
            headers,
            body: JSON.stringify({
              item_name: itemName,
              category: cat.name || cat.category || null,
              unit_cost: unitCost,
              unit: item.unit || 'ea',
              labor_hours: 0,
              supplier: (item.mfg || item.manufacturer || '').substring(0, 200) || null,
              notes: `Auto-saved from: ${projectLabel} (${new Date().toLocaleDateString()})`,
            }),
          });
          existingNames.add(itemName.toLowerCase());
          saved++;
        } catch (e) {
          skipped++;
        }
      }
    }

    if (saved > 0) {
      console.log(`[RateLibrary] Auto-populated ${saved} new rates from "${projectLabel}" (${skipped} skipped/existing)`);
    }
  } catch (err) {
    // Silent failure — don't interrupt the user's workflow
    console.warn('[RateLibrary] Auto-populate failed:', err.message);
  }
}

// ── AUTO-TRACK BID DECISIONS — capture estimator price adjustments for future bid intelligence ──
async function _autoTrackBidDecisions(estimateId) {
  try {
    if (!state.aiAnalysis || !state._originalPricing) return;
    const original = state._originalPricing;
    const current = state.aiAnalysis;
    const decisions = [];

    // Compare original AI-generated prices against what the estimator actually exported
    // Look at markup adjustments, category-level changes, etc.
    const origCategories = original.categories || original.material_categories || [];
    const currCategories = current.categories || current.material_categories || [];

    for (const origCat of origCategories) {
      const catName = (origCat.name || origCat.category || '').toLowerCase();
      const currCat = currCategories.find(c => (c.name || c.category || '').toLowerCase() === catName);
      if (!currCat) continue;

      const origTotal = origCat.subtotal || origCat.total || 0;
      const currTotal = currCat.subtotal || currCat.total || 0;
      if (origTotal === 0 || currTotal === origTotal) continue;

      const adjPct = ((currTotal - origTotal) / origTotal * 100);
      if (Math.abs(adjPct) < 1) continue; // Ignore tiny changes

      decisions.push({
        estimate_id: estimateId || state.currentEstimateId,
        project_name: state.projectName || 'Unknown',
        project_type: state.projectType || 'Low Voltage',
        category: origCat.name || origCat.category || 'unknown',
        original_value: origTotal,
        adjusted_value: currTotal,
        adjustment_pct: Math.round(adjPct * 10) / 10,
        reason: 'Estimator bid-day adjustment',
        decided_by: state._currentUser?.name || 'unknown',
      });
    }

    if (decisions.length === 0) return;

    const headers = { 'Content-Type': 'application/json' };
    const token = sessionStorage.getItem('sp_session_token');
    if (token) headers['X-Session-Token'] = token;
    else if (window._smartplansToken) headers['X-App-Token'] = window._smartplansToken;

    await fetch('/api/bid-decisions', {
      method: 'POST',
      headers,
      body: JSON.stringify({ items: decisions }),
    });
    console.log(`[BidDecisions] Tracked ${decisions.length} bid-day adjustment(s)`);
  } catch (err) {
    console.warn('[BidDecisions] Auto-track failed:', err.message);
  }
}

function _autoPopulateExclusions(brainResults) {
  if (!state.exclusions) state.exclusions = [];
  if (state.exclusions.length > 0) return; // User already has items — don't override

  const added = [];
  const _addUnique = (item) => {
    if (added.some(a => a.type === item.type && a.text === item.text)) return;
    item.id = item.id || crypto.randomUUID().replace(/-/g, '');
    added.push(item);
  };

  // 1. Load discipline-based defaults (what WE are bidding)
  const defaults = getDefaultExclusions(state.disciplines || []);
  defaults.forEach(d => _addUnique(d));

  // 2. Pull by_others items from AI pathway analysis (what OTHERS are covering)
  //    These are items the AI found marked "BY OTHERS", "FBO", "NIC" on the drawings
  const cableBrain = brainResults?.wave1?.CABLE_PATHWAY || brainResults?.wave1_75?.CABLE_PATHWAY || {};
  const pathways = cableBrain.pathways || [];
  pathways.forEach(p => {
    // AUDIT FIX M13: AI may return by_others as string "true" — use truthy check, not strict ===
    if (p.by_others === true || p.by_others === 'true' || p.by_others === 'yes') {
      const note = p.by_others_note || `${p.type || 'Item'} furnished and installed by others`;
      _addUnique({
        type: 'exclusion',
        text: `Excludes ${p.type || 'pathway item'} (${p.length_ft || 0} ft) — ${note}`,
        category: 'By Others (from Plans)',
        sort_order: 400
      });
    }
  });

  // 3. Pull exclusions from Annotation Reader (FBO/NIC/OFCI markings on drawings)
  const annotationReader = brainResults?.wave1?.ANNOTATION_READER || brainResults?.wave1_75?.ANNOTATION_READER || {};
  if (annotationReader.exclusions && Array.isArray(annotationReader.exclusions)) {
    annotationReader.exclusions.forEach(ex => {
      const txt = typeof ex === 'string' ? ex : `${ex.item || ''} — ${ex.note || 'BY OTHERS'}${ex.sheet_id ? ' (Sheet ' + ex.sheet_id + ')' : ''}`;
      if (txt) {
        _addUnique({
          type: 'exclusion',
          text: txt,
          category: 'By Others (from Plans)',
          sort_order: 410
        });
      }
    });
  }

  // 4. Pull assumptions from Financial Engine (AI-identified project assumptions)
  const financialEngine = brainResults?.wave2_25?.FINANCIAL_ENGINE || brainResults?.wave2?.FINANCIAL_ENGINE || {};
  if (financialEngine.exclusions && Array.isArray(financialEngine.exclusions)) {
    financialEngine.exclusions.forEach(ex => {
      const txt = typeof ex === 'string' ? ex : (ex.description || ex.text || '');
      if (txt) _addUnique({ type: 'exclusion', text: txt, category: 'AI-Identified', sort_order: 500 });
    });
  }
  if (financialEngine.assumptions && Array.isArray(financialEngine.assumptions)) {
    financialEngine.assumptions.forEach(a => {
      const txt = typeof a === 'string' ? a : (a.description || a.text || '');
      if (txt) _addUnique({ type: 'assumption', text: txt, category: 'AI-Identified', sort_order: 500 });
    });
  }

  // 5. Project-specific smart exclusions based on project type
  const projName = (state.projectName || '').toLowerCase();
  const projType = (state.projectType || '').toLowerCase();
  const combined = `${projName} ${projType}`;
  if (/\bva\b|veteran|vamc/i.test(combined)) {
    _addUnique({ type: 'assumption', text: 'Assumes VA IT infrastructure (network switches, servers, UPS) is furnished by VA OIT', category: 'VA-Specific', sort_order: 600 });
    _addUnique({ type: 'assumption', text: 'Assumes VA will provide network configurations, VLANs, and IP addresses prior to commissioning', category: 'VA-Specific', sort_order: 601 });
    _addUnique({ type: 'exclusion', text: 'Excludes integration with existing VA campus backbone or MPLS network', category: 'VA-Specific', sort_order: 602 });
    _addUnique({ type: 'clarification', text: 'All work subject to VA construction safety standards and ICRA requirements', category: 'VA-Specific', sort_order: 603 });
    _addUnique({ type: 'clarification', text: 'Davis-Bacon prevailing wage rates apply per federal contract requirements', category: 'VA-Specific', sort_order: 604 });
  }
  if (/hospital|medical|healthcare|clinic/i.test(combined)) {
    _addUnique({ type: 'assumption', text: 'Assumes ICRA (Infection Control Risk Assessment) barriers provided by GC when working in patient areas', category: 'Healthcare', sort_order: 610 });
    _addUnique({ type: 'exclusion', text: 'Excludes after-hours or weekend work for occupied patient areas (priced at standard hours unless noted)', category: 'Healthcare', sort_order: 611 });
  }

  // Assign to state
  state.exclusions = added;
  console.log(`[SmartPlans] Auto-populated ${added.length} exclusions/assumptions/clarifications (${state.disciplines.length} disciplines)`);

  // Sync to API if estimate exists
  if (state.estimateId && added.length > 0) {
    fetch(`/api/estimates/${state.estimateId}/exclusions`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'X-App-Token': _appToken, 'X-Session-Token': _sessionToken },
      body: JSON.stringify(added)
    }).catch(err => console.warn('[SmartPlans] Failed to sync auto-populated exclusions:', err));
  }
}

