// ═══ COST-PER-SF BENCHMARK CARD — Industry $/SF comparison ═══
function buildCostPerSFCard(st) {
  if (st._quantitiesUnverified) return ''; // Suppressed — see blocking root-cause card
  const data = st._costPerSF;
  if (!data) return '';

  const ratingColors = { within_range: '#22c55e', below_range: '#f59e0b', above_range: '#f59e0b', suspiciously_low: '#ef4444', suspiciously_high: '#ef4444' };
  const ratingLabels = { within_range: 'WITHIN RANGE', below_range: 'BELOW RANGE', above_range: 'ABOVE RANGE', suspiciously_low: 'SUSPICIOUSLY LOW', suspiciously_high: 'SUSPICIOUSLY HIGH' };
  const color = ratingColors[data.rating] || '#6366f1';
  const label = ratingLabels[data.rating] || data.rating;

  // Calculate gauge position (0-100)
  const gaugePos = Math.min(100, Math.max(0, data.percentile));

  return `
    <div class="info-card" style="border-left:3px solid ${color};">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;">
        <h3 class="info-card-title" style="margin:0;">📊 COST-PER-SF BENCHMARK</h3>
        <span style="font-size:11px;padding:3px 10px;border-radius:8px;background:${color}22;color:${color};font-weight:700;">${label}</span>
      </div>
      <div style="display:flex;align-items:baseline;gap:6px;margin-bottom:8px;">
        <span style="font-size:28px;font-weight:900;color:${color};">$${data.cost_per_sf.toFixed(2)}</span>
        <span style="font-size:13px;color:var(--text-secondary);">/SF</span>
      </div>
      <div style="font-size:12px;color:var(--text-secondary);margin-bottom:12px;">
        ${esc(data.building_type)} | ${(data.total_sf).toLocaleString()} SF | BOM Total: $${(data.grand_total).toLocaleString()}
      </div>
      <div style="position:relative;height:24px;background:linear-gradient(90deg,#ef4444 0%,#f59e0b 20%,#22c55e 35%,#22c55e 65%,#f59e0b 80%,#ef4444 100%);border-radius:12px;margin-bottom:6px;overflow:visible;">
        <div style="position:absolute;left:${gaugePos}%;top:-2px;transform:translateX(-50%);width:4px;height:28px;background:#1e1e2e;border-radius:2px;box-shadow:0 0 6px rgba(0,0,0,0.3);"></div>
      </div>
      <div style="display:flex;justify-content:space-between;font-size:11px;color:var(--text-secondary);">
        <span>$${data.benchmark_low}/SF</span>
        <span>$${data.benchmark_mid}/SF (mid)</span>
        <span>$${data.benchmark_high}/SF</span>
      </div>
      <div style="margin-top:10px;padding:8px 12px;background:rgba(0,0,0,0.03);border-radius:8px;font-size:12px;color:var(--text-secondary);font-style:italic;">
        ${esc(data.analysis)}
      </div>
    </div>`;
}

// ═══ QUANTITY ANOMALY CARD — Statistical outlier detection ═══
function buildQuantityAnomalyCard(st) {
  if (st._quantitiesUnverified) return ''; // Suppressed — see blocking root-cause card
  const anomalies = st._quantityAnomalies || [];
  if (anomalies.length === 0) return '';
  const isOpen = st._anomaliesOpen || false;

  const severityIcons = { warning: '⚠️', info: 'ℹ️', critical: '🔴' };
  const severityColors = { warning: '#f59e0b', info: '#6366f1', critical: '#ef4444' };

  return `
    <div class="info-card" style="border-left:3px solid #f59e0b;background:linear-gradient(135deg,rgba(245,158,11,0.04),rgba(239,68,68,0.02));">
      <div style="display:flex;align-items:center;justify-content:space-between;cursor:pointer;" id="anomaly-toggle">
        <h3 class="info-card-title" style="margin:0;">🔍 QUANTITY ANOMALY DETECTOR — ${anomalies.length} Flag${anomalies.length !== 1 ? 's' : ''}</h3>
        <div style="display:flex;align-items:center;gap:8px;">
          <span style="font-size:11px;padding:3px 10px;border-radius:8px;background:rgba(245,158,11,0.12);color:#f59e0b;font-weight:700;">DETERMINISTIC</span>
          <span style="transform:rotate(${isOpen ? '180' : '0'}deg);transition:transform 0.2s;">▼</span>
        </div>
      </div>
      ${isOpen ? `
        <div style="margin-top:12px;font-size:12px;color:var(--text-secondary);margin-bottom:12px;font-style:italic;">
          Statistical analysis flagged these items as potential outliers. Review each one — some may be legitimate.
        </div>
        <div style="display:flex;flex-direction:column;gap:6px;">
          ${anomalies.map(a => `
            <div style="display:flex;align-items:flex-start;gap:8px;padding:8px 12px;background:rgba(${a.severity === 'warning' ? '245,158,11' : a.severity === 'critical' ? '239,68,68' : '99,102,241'},0.04);border-radius:8px;border-left:2px solid ${severityColors[a.severity] || '#6366f1'};">
              <span style="font-size:14px;flex-shrink:0;">${severityIcons[a.severity] || 'ℹ️'}</span>
              <div>
                <div style="font-size:12px;font-weight:600;color:var(--text-primary);">${esc(a.item)}</div>
                <div style="font-size:11px;color:var(--text-secondary);margin-top:2px;">${esc(a.detail)}</div>
                <div style="font-size:11px;color:${severityColors[a.severity] || '#6366f1'};margin-top:2px;font-style:italic;">${esc(a.suggestion)}</div>
              </div>
            </div>
          `).join('')}
        </div>
      ` : ''}
    </div>`;
}

// ═══ SPEC COMPLIANCE CARD — Shows spec vs BOM gap analysis ═══
function buildSpecComplianceCard(st) {
  const sc = st._specCompliance;
  if (!sc) return '';
  const isOpen = st._specComplianceOpen || false;
  const gaps = sc.gaps || [];
  const critical = gaps.filter(g => g.severity === 'critical');
  const warnings = gaps.filter(g => g.severity === 'warning');
  const met = gaps.filter(g => g.status === 'met');
  const missing = gaps.filter(g => g.status === 'missing');
  const scoreColor = (sc.compliance_score || 0) >= 80 ? '#22c55e' : (sc.compliance_score || 0) >= 60 ? '#f59e0b' : '#ef4444';
  const totalMissingCost = missing.reduce((s, g) => s + (g.estimated_cost_if_missing || 0), 0);

  return `
    <div class="info-card" style="border-left:3px solid #14b8a6;background:linear-gradient(135deg,rgba(20,184,166,0.04),rgba(99,102,241,0.02));">
      <div style="display:flex;align-items:center;justify-content:space-between;cursor:pointer;" id="spec-compliance-toggle">
        <h3 class="info-card-title" style="margin:0;">📜 SPEC COMPLIANCE CHECKER</h3>
        <div style="display:flex;align-items:center;gap:8px;">
          <span style="font-size:11px;padding:3px 10px;border-radius:8px;background:${scoreColor}22;color:${scoreColor};font-weight:700;">${sc.compliance_score || 0}%</span>
          ${critical.length > 0 ? `<span style="font-size:11px;padding:2px 6px;border-radius:4px;background:rgba(239,68,68,0.12);color:#ef4444;font-weight:600;">${critical.length} critical</span>` : ''}
          <span style="transform:rotate(${isOpen ? '180' : '0'}deg);transition:transform 0.2s;">▼</span>
        </div>
      </div>
      ${isOpen ? `
        <div style="margin-top:16px;">
          <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:16px;">
            <div style="padding:8px;background:rgba(20,184,166,0.06);border-radius:8px;text-align:center;">
              <div style="font-size:16px;font-weight:800;color:#14b8a6;">${sc.spec_requirements_checked || 0}</div>
              <div style="font-size:10px;color:var(--text-secondary);text-transform:uppercase;">Checked</div>
            </div>
            <div style="padding:8px;background:rgba(34,197,94,0.06);border-radius:8px;text-align:center;">
              <div style="font-size:16px;font-weight:800;color:#22c55e;">${sc.requirements_met || 0}</div>
              <div style="font-size:10px;color:var(--text-secondary);text-transform:uppercase;">Met</div>
            </div>
            <div style="padding:8px;background:rgba(239,68,68,0.06);border-radius:8px;text-align:center;">
              <div style="font-size:16px;font-weight:800;color:#ef4444;">${sc.requirements_missing || 0}</div>
              <div style="font-size:10px;color:var(--text-secondary);text-transform:uppercase;">Missing</div>
            </div>
            <div style="padding:8px;background:rgba(245,158,11,0.06);border-radius:8px;text-align:center;">
              <div style="font-size:16px;font-weight:800;color:#f59e0b;">$${totalMissingCost.toLocaleString()}</div>
              <div style="font-size:10px;color:var(--text-secondary);text-transform:uppercase;">At Risk</div>
            </div>
          </div>
          ${missing.length > 0 ? `
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#ef4444;margin-bottom:6px;font-weight:600;">Missing Requirements</div>
            <div style="display:flex;flex-direction:column;gap:4px;margin-bottom:16px;">
              ${missing.slice(0, 15).map(g => `
                <div style="display:flex;align-items:flex-start;gap:8px;padding:6px 10px;background:rgba(239,68,68,0.04);border-radius:6px;border-left:2px solid ${g.severity === 'critical' ? '#ef4444' : '#f59e0b'};">
                  <span style="font-size:12px;flex-shrink:0;">${g.severity === 'critical' ? '🔴' : '🟡'}</span>
                  <div style="flex:1;min-width:0;">
                    <div style="font-size:12px;color:var(--text-primary);font-weight:500;">${esc(g.requirement || '')}</div>
                    <div style="font-size:11px;color:var(--text-secondary);margin-top:2px;">Section ${esc(g.spec_section || '?')} | Est. $${(g.estimated_cost_if_missing || 0).toLocaleString()}</div>
                  </div>
                </div>
              `).join('')}
            </div>
          ` : ''}
          ${(sc.testing_requirements || []).length > 0 ? `
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#0ea5e9;margin-bottom:6px;font-weight:600;">Testing Requirements</div>
            <div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:12px;">
              ${(sc.testing_requirements || []).map(t => `
                <span style="font-size:11px;padding:4px 8px;border-radius:6px;background:${t.in_bom ? 'rgba(34,197,94,0.1);color:#22c55e' : 'rgba(239,68,68,0.1);color:#ef4444'};">${esc(t.requirement?.substring(0, 40) || '?')} (${t.labor_hours_estimate || '?'}h) ${t.in_bom ? '✓' : '✗'}</span>
              `).join('')}
            </div>
          ` : ''}
        </div>
      ` : ''}
    </div>`;
}

// ═══════════════════════════════════════════════════════════════
// v5.127.0 BID READINESS SCORE
//
// Combines every quality signal SmartPlans produces into a single
// 0-100 score that tells the estimator how much manual review their
// bid needs. The trophy feature: no competitor shows this.
//
// Formula (weighted sum, all normalized to 0-100):
//   40% — Confidence grade distribution (A/B/C/D percentages)
//   20% — Sheet coverage (from Wave 0.3 Sheet Inventory Guard)
//   15% — Discipline coverage (0 penalty if any zero-count disciplines)
//   10% — Open clarification questions (penalty for unanswered)
//   10% — Spec compliance score (from SPEC_COMPLIANCE_CHECKER)
//    5% — Critical scope delineations addressed
//
// Returns { score, grade, label, color, factors }
// ═══════════════════════════════════════════════════════════════
function computeBidReadinessScore(st) {
  if (!st || !st.analysisComplete) {
    return { score: 0, grade: 'N/A', label: 'Analysis Not Run', color: '#64748b', factors: [] };
  }

  // Short-circuit: if quantities are unverified, readiness is always 0.
  if (st._quantitiesUnverified) {
    return {
      score: 0,
      grade: 'F',
      label: 'QUANTITIES NOT VERIFIED',
      color: '#ef4444',
      factors: [
        { name: 'Quantities unverified', points: 0, max: 100, note: st._quantitiesUnverifiedReason || 'Symbol Scanner could not verify counts. See blocking card below.' }
      ],
    };
  }

  const factors = [];

  // ─── Factor 1: Confidence grade distribution (40%) ───
  const cs = st._confidenceScoring;
  let confidenceScore = 50; // Default neutral if no scoring data
  if (cs && typeof cs.avgScore === 'number') {
    confidenceScore = Math.max(0, Math.min(100, cs.avgScore));
  }
  factors.push({
    name: 'Confidence Grade',
    points: Math.round(confidenceScore * 0.40),
    max: 40,
    note: cs ? `${cs.overallGrade || '?'} overall · ${cs.totalItems || 0} items graded · ${cs.avgScore || 0}/100 avg` : 'No per-item scoring available',
  });

  // ─── Factor 2: Sheet coverage (20%) ───
  const si = st._sheetInventory;
  let sheetScore = 50;
  if (si && typeof si.coverage_pct === 'number') {
    sheetScore = Math.max(0, Math.min(100, si.coverage_pct));
  } else if (si && si.index_found === false) {
    sheetScore = 60; // no penalty if the drawing index wasn't extractable
  }
  factors.push({
    name: 'Sheet Coverage',
    points: Math.round(sheetScore * 0.20),
    max: 20,
    note: si
      ? `${si.coverage_pct || 0}% of relevant sheets uploaded (${si.uploaded_relevant_sheet_count || 0}/${si.total_relevant_sheets || 0})`
      : 'Sheet Inventory Guard did not run',
  });

  // ─── Factor 3: Discipline coverage (15%) ───
  const gaps = Array.isArray(st._disciplineCoverageGaps) ? st._disciplineCoverageGaps : [];
  const totalDisc = Array.isArray(st.disciplines) ? st.disciplines.length : 0;
  const disciplineScore = totalDisc > 0
    ? Math.max(0, 100 - (gaps.length / totalDisc) * 100)
    : 50;
  factors.push({
    name: 'Discipline Coverage',
    points: Math.round(disciplineScore * 0.15),
    max: 15,
    note: gaps.length === 0
      ? `All ${totalDisc} selected disciplines have device counts`
      : `${gaps.length} zero-count discipline(s): ${gaps.join(', ')}`,
  });

  // ─── Factor 4: Open clarification questions (10%) ───
  const questions = Array.isArray(st._clarificationQuestions) ? st._clarificationQuestions : [];
  const highSev = questions.filter(q => q.severity === 'high' || q.severity === 'critical');
  const answered = st._clarificationAnswers || {};
  const unanswered = highSev.filter(q => !answered[q.id]);
  const clarScore = highSev.length === 0
    ? 100
    : Math.max(0, 100 - (unanswered.length / highSev.length) * 100);
  factors.push({
    name: 'Open Clarifications',
    points: Math.round(clarScore * 0.10),
    max: 10,
    note: highSev.length === 0
      ? 'No ambiguous symbols flagged'
      : `${unanswered.length} of ${highSev.length} high-severity questions unanswered`,
  });

  // ─── Factor 5: Spec compliance (10%) ───
  const sc = st._specCompliance;
  let specScore = 75; // default if spec check didn't run
  if (sc && typeof sc.compliance_score === 'number') {
    specScore = Math.max(0, Math.min(100, sc.compliance_score));
  }
  factors.push({
    name: 'Spec Compliance',
    points: Math.round(specScore * 0.10),
    max: 10,
    note: sc
      ? `${sc.compliance_score || 0}/100 — ${sc.requirements_met || 0} met, ${(sc.gaps || []).filter(g => g.severity === 'critical').length} critical gaps`
      : 'Spec Compliance Checker did not run',
  });

  // ─── Factor 6: Scope delineations addressed (5%) ───
  const sd = st._scopeDelineations;
  const criticalDelineations = (sd?.delineations || []).filter(d => d.severity === 'critical');
  const autoRemoved = Array.isArray(st._autoRemovedDisciplines) ? st._autoRemovedDisciplines.length : 0;
  // If critical delineations exist and we auto-removed the affected disciplines,
  // that counts as "addressed"
  const delineationScore = criticalDelineations.length === 0
    ? 100
    : Math.max(60, 100 - (criticalDelineations.length - autoRemoved) * 10);
  factors.push({
    name: 'Scope Delineations',
    points: Math.round(delineationScore * 0.05),
    max: 5,
    note: criticalDelineations.length === 0
      ? 'No critical scope delineations found'
      : `${criticalDelineations.length} critical found · ${autoRemoved} disciplines auto-removed`,
  });

  // ─── Total + grade ───
  const total = factors.reduce((s, f) => s + f.points, 0);
  const score = Math.min(100, Math.max(0, total));

  let grade, label, color;
  if (score >= 90)      { grade = 'A'; label = 'READY TO SEND';        color = '#10b981'; }
  else if (score >= 80) { grade = 'B'; label = 'LIGHT REVIEW NEEDED';  color = '#22c55e'; }
  else if (score >= 70) { grade = 'C'; label = 'MODERATE REVIEW';      color = '#f59e0b'; }
  else if (score >= 55) { grade = 'D'; label = 'SIGNIFICANT REVIEW';   color = '#f97316'; }
  else                  { grade = 'F'; label = 'NEEDS SIGNIFICANT FIXES'; color = '#ef4444'; }

  return { score, grade, label, color, factors };
}

// ═══ BID READINESS SCORE CARD — prominent top-of-page display ═══
function buildBidReadinessCard(st) {
  const result = computeBidReadinessScore(st);
  if (!st.analysisComplete) return '';

  const circumference = 2 * Math.PI * 54; // radius 54 → ~339.3
  const dashoffset = circumference - (result.score / 100) * circumference;

  return `
    <div id="bid-readiness-card" style="margin:18px 0 22px 0;padding:24px 28px;background:linear-gradient(135deg,#0f172a 0%,#1e293b 100%);border-radius:14px;border:2px solid ${result.color};box-shadow:0 8px 32px rgba(15,23,42,0.3);display:flex;align-items:center;gap:28px;flex-wrap:wrap;">

      <!-- Score Ring -->
      <div style="flex-shrink:0;position:relative;width:140px;height:140px;">
        <svg width="140" height="140" viewBox="0 0 140 140">
          <circle cx="70" cy="70" r="54" stroke="rgba(255,255,255,0.08)" stroke-width="14" fill="none"></circle>
          <circle cx="70" cy="70" r="54" stroke="${result.color}" stroke-width="14" fill="none"
                  stroke-dasharray="${circumference}" stroke-dashoffset="${dashoffset}"
                  stroke-linecap="round" transform="rotate(-90 70 70)"
                  style="transition:stroke-dashoffset 1s ease-out;filter:drop-shadow(0 0 8px ${result.color}66);"></circle>
        </svg>
        <div style="position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;">
          <div style="font-size:42px;font-weight:900;color:${result.color};line-height:1;font-family:'Playfair Display','Georgia',serif;">${result.score}</div>
          <div style="font-size:10px;color:rgba(255,255,255,0.5);letter-spacing:2px;margin-top:2px;">/ 100</div>
        </div>
      </div>

      <!-- Label + Breakdown -->
      <div style="flex:1;min-width:280px;">
        <div style="font-size:10px;font-weight:800;color:#EBB328;letter-spacing:3px;text-transform:uppercase;margin-bottom:6px;">SmartPlans · Bid Readiness</div>
        <div style="font-size:24px;font-weight:900;color:${result.color};line-height:1.2;margin-bottom:4px;">${result.label}</div>
        <div style="font-size:13px;color:rgba(255,255,255,0.6);margin-bottom:14px;">
          Grade <strong style="color:${result.color};">${result.grade}</strong> — based on confidence, coverage, clarifications, and spec compliance
        </div>

        <!-- Factor breakdown -->
        <div style="display:flex;flex-wrap:wrap;gap:6px;">
          ${result.factors.map(f => {
            const pct = f.max > 0 ? (f.points / f.max) : 0;
            const color = pct >= 0.85 ? '#10b981' : pct >= 0.65 ? '#22c55e' : pct >= 0.45 ? '#f59e0b' : '#ef4444';
            return `<div style="flex:1;min-width:120px;padding:8px 10px;background:rgba(255,255,255,0.04);border-left:3px solid ${color};border-radius:4px;" title="${esc(f.note)}">
              <div style="font-size:9px;color:rgba(255,255,255,0.5);text-transform:uppercase;letter-spacing:1px;font-weight:700;">${esc(f.name)}</div>
              <div style="font-size:15px;font-weight:800;color:#ffffff;margin-top:2px;">${f.points}<span style="font-size:10px;color:rgba(255,255,255,0.45);">/${f.max}</span></div>
            </div>`;
          }).join('')}
        </div>
      </div>

      ${result.score < 70 ? `
        <div style="flex-basis:100%;padding:12px 16px;background:rgba(239,68,68,0.12);border-left:3px solid #ef4444;border-radius:6px;margin-top:4px;">
          <div style="font-size:11px;font-weight:800;color:#ef4444;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px;">⚠ Bid Not Ready</div>
          <div style="font-size:12.5px;color:rgba(255,255,255,0.85);line-height:1.55;">
            This bid needs manual review before you send it. Scroll down to the Estimator Checklist card to see exactly what needs fixing.
          </div>
        </div>` : result.score < 85 ? `
        <div style="flex-basis:100%;padding:12px 16px;background:rgba(245,158,11,0.12);border-left:3px solid #f59e0b;border-radius:6px;margin-top:4px;">
          <div style="font-size:11px;font-weight:800;color:#f59e0b;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px;">Review Recommended</div>
          <div style="font-size:12.5px;color:rgba(255,255,255,0.85);line-height:1.55;">
            Verify the items flagged in the Confidence Scoring and Estimator Checklist cards below before sending.
          </div>
        </div>` : `
        <div style="flex-basis:100%;padding:12px 16px;background:rgba(16,185,129,0.12);border-left:3px solid #10b981;border-radius:6px;margin-top:4px;">
          <div style="font-size:11px;font-weight:800;color:#10b981;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px;">✓ Ready to Send</div>
          <div style="font-size:12.5px;color:rgba(255,255,255,0.85);line-height:1.55;">
            All quality signals are green. Use the "Generate Full Proposal" or "Generate Executive Proposal" buttons above, or export the BOM to Excel.
          </div>
        </div>`}
    </div>
  `;
}

// ═══ CONFIDENCE SCORING CARD — Per-item grade distribution ═══
function buildConfidenceScoringCard(st) {
  if (st._quantitiesUnverified) return ''; // Suppressed — see blocking root-cause card
  const cs = st._confidenceScoring;
  if (!cs) return '';

  const grades = cs.grades || {};
  const total = cs.totalItems || 1;
  const pctA = Math.round((grades.A || 0) / total * 100);
  const pctB = Math.round((grades.B || 0) / total * 100);
  const pctC = Math.round((grades.C || 0) / total * 100);
  const pctD = Math.round((grades.D || 0) / total * 100);

  const overallColor = cs.overallGrade === 'A' ? '#22c55e' : cs.overallGrade === 'B' ? '#0ea5e9' : cs.overallGrade === 'C' ? '#f59e0b' : '#ef4444';

  return `
    <div class="info-card" style="border-left:3px solid ${overallColor};">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;">
        <h3 class="info-card-title" style="margin:0;">🎯 BOM CONFIDENCE SCORING</h3>
        <div style="display:flex;align-items:center;gap:8px;">
          <span style="font-size:18px;font-weight:900;color:${overallColor};">${cs.overallGrade}</span>
          <span style="font-size:11px;color:var(--text-secondary);">(${cs.avgScore}/100 avg)</span>
        </div>
      </div>
      <div style="font-size:12px;color:var(--text-secondary);margin-bottom:12px;">
        ${cs.totalItems} line items graded by consensus agreement, verification results, and anomaly flags
      </div>
      <div style="display:flex;gap:2px;height:24px;border-radius:6px;overflow:hidden;margin-bottom:8px;">
        ${pctA > 0 ? `<div style="width:${pctA}%;background:#22c55e;display:flex;align-items:center;justify-content:center;"><span style="font-size:10px;color:white;font-weight:700;">${grades.A}</span></div>` : ''}
        ${pctB > 0 ? `<div style="width:${pctB}%;background:#0ea5e9;display:flex;align-items:center;justify-content:center;"><span style="font-size:10px;color:white;font-weight:700;">${grades.B}</span></div>` : ''}
        ${pctC > 0 ? `<div style="width:${pctC}%;background:#f59e0b;display:flex;align-items:center;justify-content:center;"><span style="font-size:10px;color:white;font-weight:700;">${grades.C}</span></div>` : ''}
        ${pctD > 0 ? `<div style="width:${pctD}%;background:#ef4444;display:flex;align-items:center;justify-content:center;"><span style="font-size:10px;color:white;font-weight:700;">${grades.D}</span></div>` : ''}
      </div>
      <div style="display:flex;justify-content:space-between;font-size:11px;">
        <span style="color:#22c55e;font-weight:600;">A: ${grades.A || 0} (${pctA}%)</span>
        <span style="color:#0ea5e9;font-weight:600;">B: ${grades.B || 0} (${pctB}%)</span>
        <span style="color:#f59e0b;font-weight:600;">C: ${grades.C || 0} (${pctC}%)</span>
        <span style="color:#ef4444;font-weight:600;">D: ${grades.D || 0} (${pctD}%)</span>
      </div>
      <div style="margin-top:10px;padding:8px 12px;background:rgba(0,0,0,0.03);border-radius:8px;font-size:11px;color:var(--text-secondary);">
        <strong>A</strong> = High confidence (verified by consensus, no flags) | <strong>B</strong> = Good (minor flags) | <strong>C</strong> = Review recommended | <strong>D</strong> = Low confidence (multiple flags)
      </div>

      ${Array.isArray(cs.worstItems) && cs.worstItems.length > 0 ? `
      <div style="margin-top:14px;padding-top:14px;border-top:1px solid rgba(0,0,0,0.06);">
        <div style="font-size:11px;font-weight:800;color:rgba(0,0,0,0.55);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px;">
          ⚠ ${cs.worstItems.length} item${cs.worstItems.length === 1 ? '' : 's'} need review (verify these before sending)
        </div>
        <div style="max-height:260px;overflow-y:auto;">
          <table style="width:100%;border-collapse:collapse;font-size:11.5px;">
            <thead>
              <tr style="background:rgba(0,0,0,0.03);">
                <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.08);font-weight:700;color:rgba(0,0,0,0.55);font-size:10px;text-transform:uppercase;letter-spacing:0.5px;">Grade</th>
                <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.08);font-weight:700;color:rgba(0,0,0,0.55);font-size:10px;text-transform:uppercase;letter-spacing:0.5px;">Item</th>
                <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.08);font-weight:700;color:rgba(0,0,0,0.55);font-size:10px;text-transform:uppercase;letter-spacing:0.5px;">Category</th>
                <th style="text-align:right;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.08);font-weight:700;color:rgba(0,0,0,0.55);font-size:10px;text-transform:uppercase;letter-spacing:0.5px;">Qty</th>
                <th style="text-align:right;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.08);font-weight:700;color:rgba(0,0,0,0.55);font-size:10px;text-transform:uppercase;letter-spacing:0.5px;">Cost</th>
                <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.08);font-weight:700;color:rgba(0,0,0,0.55);font-size:10px;text-transform:uppercase;letter-spacing:0.5px;">Why</th>
              </tr>
            </thead>
            <tbody>
              ${cs.worstItems.map(w => {
                const gradeColor = w.grade === 'D' ? '#ef4444' : '#f59e0b';
                return `<tr style="border-bottom:1px solid rgba(0,0,0,0.04);">
                  <td style="padding:7px 10px;"><span style="display:inline-block;padding:2px 8px;border-radius:10px;background:${gradeColor};color:#fff;font-size:10px;font-weight:800;">${esc(w.grade)} (${w.score})</span></td>
                  <td style="padding:7px 10px;font-weight:600;color:rgba(0,0,0,0.8);">${esc(String(w.name).substring(0, 50))}</td>
                  <td style="padding:7px 10px;color:rgba(0,0,0,0.6);font-size:11px;">${esc(String(w.category).substring(0, 30))}</td>
                  <td style="padding:7px 10px;text-align:right;font-family:'JetBrains Mono',monospace;color:rgba(0,0,0,0.7);">${w.qty} ${esc(w.unit || 'ea')}</td>
                  <td style="padding:7px 10px;text-align:right;font-family:'JetBrains Mono',monospace;color:rgba(0,0,0,0.7);">$${Math.round(w.ext_cost).toLocaleString()}</td>
                  <td style="padding:7px 10px;color:rgba(0,0,0,0.6);font-size:11px;">${esc((w.reasons || []).join(' · ') || '—')}</td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>
        </div>
        <div style="margin-top:10px;padding:8px 12px;background:rgba(235,179,40,0.08);border-left:3px solid #EBB328;border-radius:6px;font-size:11px;color:rgba(0,0,0,0.7);line-height:1.5;">
          💡 <strong>Workflow:</strong> Review each item above, verify the count on the plans, adjust in the BOM table if needed, then re-export. Items flagged C or D contribute to the Bid Readiness Score at the top of this page.
        </div>
      </div>
      ` : `
      <div style="margin-top:12px;padding:10px 14px;background:rgba(16,185,129,0.06);border-left:3px solid #10b981;border-radius:6px;font-size:12px;color:rgba(0,0,0,0.65);">
        ✓ No items flagged for review — every line item scored B or better.
      </div>
      `}
    </div>`;
}

// ═══ PROPOSAL NARRATIVE CARD — Persuasive winning proposal from Wave 4.1 ═══
function buildProposalNarrativeCard(st) {
  const pn = st._proposalNarrative;
  if (!pn) return '';

  const isOpen = st._proposalOpen || false;

  // Collect non-empty sections
  const sections = [
    { key: 'executive_summary', title: 'Executive Summary', icon: '🎯', color: '#6366f1' },
    { key: 'proof_of_understanding', title: 'Proof of Understanding', icon: '🔍', color: '#8b5cf6' },
    { key: 'technical_approach', title: 'Technical Approach & Methodology', icon: '⚙️', color: '#0ea5e9' },
    { key: 'risk_mitigation', title: 'Risk Mitigation & Value Engineering', icon: '🛡️', color: '#14b8a6' },
    { key: 'quality_assurance', title: 'Quality Assurance & Compliance', icon: '✅', color: '#22c55e' },
    { key: 'relevant_experience', title: 'Relevant Experience', icon: '🏗️', color: '#f59e0b' },
    { key: 'why_us', title: 'Why Us — The Decision Made Simple', icon: '🏆', color: '#ef4444' },
    { key: 'closing_statement', title: 'Closing Statement', icon: '🤝', color: '#6366f1' },
  ].filter(s => pn[s.key]);

  const sectionCount = sections.length;
  const wordCount = sections.reduce((sum, s) => sum + (pn[s.key] || '').split(/\s+/).length, 0);

  // Format paragraph text — convert markdown-like bold and newlines
  const fmtText = (text) => {
    if (!text) return '';
    return esc(text)
      .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
      .replace(/\n\n/g, '</p><p style="margin:8px 0;line-height:1.7;">')
      .replace(/\n- /g, '</p><div style="padding-left:16px;margin:4px 0;"><span style="color:#6366f1;margin-right:6px;">▸</span>')
      .replace(/\n(\d+)\. /g, '</p><div style="padding-left:16px;margin:4px 0;"><span style="color:#6366f1;margin-right:6px;">$1.</span>');
  };

  return `
    <div class="info-card" style="border-left:3px solid #f59e0b;background:linear-gradient(135deg,rgba(245,158,11,0.04),rgba(99,102,241,0.04));">
      <div style="display:flex;align-items:center;justify-content:space-between;cursor:pointer;" id="proposal-narrative-toggle">
        <h3 class="info-card-title" style="margin:0;">🏆 WINNING PROPOSAL NARRATIVE</h3>
        <div style="display:flex;align-items:center;gap:8px;">
          <span style="font-size:11px;padding:2px 8px;border-radius:4px;background:rgba(245,158,11,0.15);color:#f59e0b;font-weight:600;">${sectionCount} sections</span>
          <span style="font-size:11px;color:var(--text-secondary);">~${wordCount.toLocaleString()} words</span>
          <span style="transform:rotate(${isOpen ? '180' : '0'}deg);transition:transform 0.2s;">▼</span>
        </div>
      </div>
      ${isOpen ? `
        <div style="margin-top:16px;">
          <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;">
            <div style="font-size:12px;color:var(--text-secondary);font-style:italic;">AI-generated proposal draft — review and customize before submission</div>
            <button id="proposal-copy-btn" style="display:flex;align-items:center;gap:4px;padding:6px 14px;border-radius:8px;border:1px solid rgba(245,158,11,0.3);background:rgba(245,158,11,0.08);color:#f59e0b;font-size:12px;font-weight:600;cursor:pointer;">
              <i data-lucide="copy" style="width:14px;height:14px;"></i> Copy Proposal
            </button>
          </div>
          ${sections.map(s => `
            <div style="margin-bottom:20px;">
              <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;padding-bottom:6px;border-bottom:1px solid rgba(0,0,0,0.08);">
                <span style="font-size:16px;">${s.icon}</span>
                <h4 style="margin:0;font-size:14px;font-weight:700;color:${s.color};text-transform:uppercase;letter-spacing:0.5px;">${esc(s.title)}</h4>
              </div>
              <div style="font-size:13px;color:var(--text-primary);line-height:1.7;padding:0 4px;">
                <p style="margin:8px 0;line-height:1.7;">${fmtText(pn[s.key])}</p>
              </div>
            </div>
          `).join('')}
          ${pn.tone_notes ? `
            <div style="margin-top:16px;padding:10px 14px;background:rgba(99,102,241,0.06);border-radius:8px;border-left:3px solid #6366f1;">
              <div style="font-size:11px;font-weight:700;color:#6366f1;text-transform:uppercase;letter-spacing:1px;margin-bottom:4px;">Tone & Strategy Notes</div>
              <div style="font-size:12px;color:var(--text-secondary);line-height:1.6;">${esc(pn.tone_notes)}</div>
            </div>
          ` : ''}
          ${pn.win_themes && pn.win_themes.length > 0 ? `
            <div style="margin-top:12px;display:flex;flex-wrap:wrap;gap:6px;">
              ${pn.win_themes.map(t => `<span style="padding:4px 10px;border-radius:12px;font-size:11px;font-weight:600;background:rgba(245,158,11,0.12);color:#f59e0b;">${esc(t)}</span>`).join('')}
            </div>
          ` : ''}
        </div>
      ` : ''}
    </div>`;
}

// ═══════════════════════════════════════════════════════════
// NEW CARDS v5.124.5 — Preflight Gates & First-Read Surfacing
// ═══════════════════════════════════════════════════════════

function buildSheetInventoryCard(st) {
  const sig = st._sheetInventory;
  if (!sig) return '';
  const coverage = parseFloat(sig.coverage_pct) || 0;
  const status = (sig.status || '').toLowerCase();
  const missing = Array.isArray(sig.missing_sheets) ? sig.missing_sheets : [];
  const indexList = Array.isArray(sig.index_sheet_list) ? sig.index_sheet_list : [];

  // Color based on status
  const statusColor = status === 'ok' ? '#10B981' : status === 'partial' ? '#F59E0B' : '#EF4444';
  const statusLabel = status === 'ok' ? '✓ FULL COVERAGE' : status === 'partial' ? '⚠ PARTIAL COVERAGE' : '⛔ INSUFFICIENT COVERAGE';
  const icon = status === 'ok' ? '📑' : status === 'insufficient' ? '⛔' : '⚠️';

  return `
    <div class="info-card" id="sheet-inventory-card" style="border-left:3px solid ${statusColor};margin-top:16px;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;cursor:pointer;" id="sheet-inv-toggle">
        <h3 class="info-card-title" style="margin:0;display:flex;align-items:center;gap:8px;">
          <span style="font-size:18px;">${icon}</span> SHEET INVENTORY GUARD
          <span style="padding:3px 10px;border-radius:10px;font-size:10px;font-weight:800;background:${statusColor};color:white;letter-spacing:0.5px;">${statusLabel}</span>
          <span style="font-size:13px;font-weight:600;color:${statusColor};">${coverage}% coverage</span>
        </h3>
        <span style="font-size:11px;color:rgba(0,0,0,0.4);text-transform:uppercase;letter-spacing:1px;">&#9660; EXPAND</span>
      </div>
      <div id="sheet-inv-body" style="display:${status === 'insufficient' ? 'block' : 'none'};">
        <div style="display:flex;gap:12px;margin-bottom:14px;flex-wrap:wrap;">
          <div style="flex:1;min-width:160px;padding:10px 14px;background:rgba(99,102,241,0.06);border-radius:8px;">
            <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);">Index Sheet</div>
            <div style="font-weight:700;font-size:13px;">${esc(sig.index_source_sheet || 'Not found')}</div>
          </div>
          <div style="flex:1;min-width:160px;padding:10px 14px;background:rgba(99,102,241,0.06);border-radius:8px;">
            <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);">Relevant Sheets</div>
            <div style="font-weight:700;font-size:13px;">${sig.uploaded_relevant_sheet_count || 0} / ${sig.total_relevant_sheets || 0} uploaded</div>
          </div>
          <div style="flex:1;min-width:160px;padding:10px 14px;background:rgba(99,102,241,0.06);border-radius:8px;">
            <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);">Total In Index</div>
            <div style="font-weight:700;font-size:13px;">${sig.total_sheets_in_index || 0} sheets published</div>
          </div>
        </div>
        ${sig.warning_to_estimator ? `
          <div style="padding:12px 16px;background:rgba(239,68,68,0.08);border-left:3px solid ${statusColor};border-radius:6px;margin-bottom:14px;">
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:${statusColor};font-weight:800;margin-bottom:4px;">Warning</div>
            <div style="font-size:13px;color:rgba(0,0,0,0.75);line-height:1.5;">${esc(sig.warning_to_estimator)}</div>
          </div>
        ` : ''}
        ${missing.length > 0 ? `
          <div style="margin-bottom:14px;">
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#EF4444;font-weight:800;margin-bottom:8px;">⚠ Missing Sheets (${missing.length})</div>
            <div style="max-height:260px;overflow-y:auto;">
              <table style="width:100%;border-collapse:collapse;font-size:12px;">
                <thead><tr style="background:rgba(239,68,68,0.06);">
                  <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">Sheet No.</th>
                  <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">Title</th>
                  <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">Why Needed</th>
                </tr></thead>
                <tbody>
                  ${missing.map(m => `<tr>
                    <td style="padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.05);font-family:monospace;font-weight:700;">${esc(m.sheet_no || '')}</td>
                    <td style="padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.05);">${esc(m.title || '')}</td>
                    <td style="padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.05);color:rgba(0,0,0,0.6);">${esc(m.why_needed || '')}</td>
                  </tr>`).join('')}
                </tbody>
              </table>
            </div>
          </div>
        ` : ''}
        ${indexList.length > 0 ? `
          <details style="margin-top:10px;">
            <summary style="cursor:pointer;font-size:11px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);font-weight:700;">Full Sheet Index (${indexList.length})</summary>
            <div style="margin-top:8px;max-height:240px;overflow-y:auto;font-family:monospace;font-size:11px;">
              ${indexList.map(s => `<div style="padding:4px 8px;border-bottom:1px solid rgba(0,0,0,0.04);${s.relevant_to_selected_disciplines ? 'background:rgba(16,185,129,0.04);' : 'opacity:0.5;'}">${esc(s.sheet_no || '')} — ${esc(s.title || '')} ${s.relevant_to_selected_disciplines ? '<span style="color:#10B981;font-weight:700;">[REQUIRED]</span>' : '<span style="color:rgba(0,0,0,0.4);">[skip]</span>'}</div>`).join('')}
            </div>
          </details>
        ` : ''}
      </div>
    </div>`;
}

function buildPrevailingWageCard(st) {
  const pw = st._prevailingWageDetection;
  if (!pw) return '';
  const required = st._prevailingWageRequired;
  const type = (st._prevailingWageType || '').toUpperCase().replace('_', '-');
  const mult = st._prevailingWageMultiplier || 1.0;
  const indicators = Array.isArray(pw.indicators) ? pw.indicators : [];
  const color = required ? '#8B5CF6' : '#10B981';
  const icon = required ? '⚖️' : '✓';
  const label = required ? `${type} REQUIRED` : 'OPEN-SHOP OK';

  return `
    <div class="info-card" id="prevailing-wage-card" style="border-left:3px solid ${color};margin-top:16px;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;cursor:pointer;" id="pw-toggle">
        <h3 class="info-card-title" style="margin:0;display:flex;align-items:center;gap:8px;">
          <span style="font-size:18px;">${icon}</span> PREVAILING WAGE DETECTION
          <span style="padding:3px 10px;border-radius:10px;font-size:10px;font-weight:800;background:${color};color:white;letter-spacing:0.5px;">${label}</span>
          ${required ? `<span style="font-size:13px;font-weight:700;color:${color};">${mult}× labor multiplier</span>` : ''}
        </h3>
        <span style="font-size:11px;color:rgba(0,0,0,0.4);text-transform:uppercase;letter-spacing:1px;">&#9660; EXPAND</span>
      </div>
      <div id="pw-body" style="display:${required ? 'block' : 'none'};">
        ${required ? `
          <div style="display:flex;gap:12px;margin-bottom:14px;flex-wrap:wrap;">
            <div style="flex:1;min-width:180px;padding:10px 14px;background:rgba(139,92,246,0.08);border-radius:8px;">
              <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);">Agency / Owner</div>
              <div style="font-weight:700;font-size:13px;">${esc(pw.agency_or_owner || 'Federal or state public project')}</div>
            </div>
            <div style="flex:1;min-width:180px;padding:10px 14px;background:rgba(139,92,246,0.08);border-radius:8px;">
              <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);">Wage Determination</div>
              <div style="font-weight:700;font-size:13px;">${esc(pw.wage_determination || 'Obtain from solicitation')}</div>
            </div>
            <div style="flex:1;min-width:180px;padding:10px 14px;background:rgba(139,92,246,0.08);border-radius:8px;">
              <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);">Rate Multiplier Applied</div>
              <div style="font-weight:700;font-size:13px;color:${color};">${mult}× base rate</div>
            </div>
          </div>
        ` : `
          <p style="color:rgba(0,0,0,0.6);font-size:13px;margin-bottom:12px;">No federal or state prevailing wage indicators detected. Labor calculator will use open-shop rates.</p>
        `}
        ${pw.warning_to_estimator ? `
          <div style="padding:12px 16px;background:rgba(139,92,246,0.06);border-left:3px solid ${color};border-radius:6px;margin-bottom:14px;">
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:${color};font-weight:800;margin-bottom:4px;">⚠ Critical Notice</div>
            <div style="font-size:13px;color:rgba(0,0,0,0.75);line-height:1.5;">${esc(pw.warning_to_estimator)}</div>
          </div>
        ` : ''}
        ${indicators.length > 0 ? `
          <div>
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);font-weight:700;margin-bottom:8px;">Detection Indicators (${indicators.length})</div>
            <div style="max-height:200px;overflow-y:auto;">
              ${indicators.map(i => `<div style="padding:8px 12px;margin-bottom:6px;background:rgba(139,92,246,0.04);border-radius:6px;">
                <div style="font-size:10px;text-transform:uppercase;color:rgba(0,0,0,0.45);font-weight:700;">${esc(i.source || 'unknown source')} · ${i.confidence || 0}% confidence</div>
                <div style="font-size:12.5px;margin-top:2px;">"${esc(i.text || '')}"</div>
              </div>`).join('')}
            </div>
          </div>
        ` : ''}
      </div>
    </div>`;
}

function buildScopeDelineationCard(st) {
  const sds = st._scopeDelineations;
  if (!sds) return '';
  const delineations = Array.isArray(sds.delineations) ? sds.delineations : [];
  if (delineations.length === 0) return '';

  const critical = delineations.filter(d => d.severity === 'critical');
  const warnings = delineations.filter(d => d.severity === 'warning');
  const ofoi = Array.isArray(sds.ofoi_items) ? sds.ofoi_items : [];
  const nic = Array.isArray(sds.nic_items) ? sds.nic_items : [];
  const roughIn = Array.isArray(sds.rough_in_only_items) ? sds.rough_in_only_items : [];

  const color = critical.length > 0 ? '#EF4444' : '#F59E0B';

  return `
    <div class="info-card" id="scope-delineation-card" style="border-left:3px solid ${color};margin-top:16px;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;cursor:pointer;" id="sd-toggle">
        <h3 class="info-card-title" style="margin:0;display:flex;align-items:center;gap:8px;">
          <span style="font-size:18px;">🛂</span> SCOPE DELINEATIONS
          <span style="padding:3px 10px;border-radius:10px;font-size:10px;font-weight:800;background:${color};color:white;letter-spacing:0.5px;">${delineations.length} FOUND</span>
          ${critical.length > 0 ? `<span style="font-size:12px;font-weight:700;color:#EF4444;">${critical.length} critical</span>` : ''}
        </h3>
        <span style="font-size:11px;color:rgba(0,0,0,0.4);text-transform:uppercase;letter-spacing:1px;">&#9660; EXPAND</span>
      </div>
      <div id="sd-body" style="display:${critical.length > 0 ? 'block' : 'none'};">
        ${Array.isArray(sds.critical_warnings) && sds.critical_warnings.length > 0 ? `
          <div style="margin-bottom:14px;">
            ${sds.critical_warnings.map(w => `<div style="padding:10px 14px;background:rgba(239,68,68,0.08);border-left:3px solid #EF4444;border-radius:6px;margin-bottom:8px;font-size:13px;color:rgba(0,0,0,0.8);font-weight:600;">⚠ ${esc(w)}</div>`).join('')}
          </div>
        ` : ''}
        <div style="display:flex;gap:12px;margin-bottom:14px;flex-wrap:wrap;">
          <div style="flex:1;min-width:140px;padding:10px 14px;background:rgba(239,68,68,0.06);border-radius:8px;">
            <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:#EF4444;font-weight:800;">OFOI</div>
            <div style="font-size:18px;font-weight:800;color:#EF4444;">${ofoi.length}</div>
            <div style="font-size:11px;color:rgba(0,0,0,0.5);">owner-furnished</div>
          </div>
          <div style="flex:1;min-width:140px;padding:10px 14px;background:rgba(245,158,11,0.06);border-radius:8px;">
            <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:#F59E0B;font-weight:800;">NIC / By Others</div>
            <div style="font-size:18px;font-weight:800;color:#F59E0B;">${nic.length}</div>
            <div style="font-size:11px;color:rgba(0,0,0,0.5);">not in contract</div>
          </div>
          <div style="flex:1;min-width:140px;padding:10px 14px;background:rgba(99,102,241,0.06);border-radius:8px;">
            <div style="font-size:10px;text-transform:uppercase;letter-spacing:1px;color:#6366F1;font-weight:800;">Rough-In Only</div>
            <div style="font-size:18px;font-weight:800;color:#6366F1;">${roughIn.length}</div>
            <div style="font-size:11px;color:rgba(0,0,0,0.5);">labor yes, no device</div>
          </div>
        </div>
        <div style="max-height:340px;overflow-y:auto;">
          <table style="width:100%;border-collapse:collapse;font-size:12px;">
            <thead><tr style="background:rgba(0,0,0,0.04);">
              <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">Type</th>
              <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">Affected Scope</th>
              <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">Exact Phrase</th>
              <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">Source</th>
              <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">BOM Correction</th>
            </tr></thead>
            <tbody>
              ${delineations.map(d => {
                const sevColor = d.severity === 'critical' ? '#EF4444' : d.severity === 'warning' ? '#F59E0B' : '#10B981';
                return `<tr>
                  <td style="padding:8px 10px;border-bottom:1px solid rgba(0,0,0,0.05);"><span style="padding:2px 8px;border-radius:10px;font-size:10px;font-weight:700;background:${sevColor};color:white;letter-spacing:0.3px;">${esc((d.phrase_type || '').toUpperCase())}</span></td>
                  <td style="padding:8px 10px;border-bottom:1px solid rgba(0,0,0,0.05);font-weight:600;">${esc(d.affected_scope || '')}</td>
                  <td style="padding:8px 10px;border-bottom:1px solid rgba(0,0,0,0.05);font-style:italic;color:rgba(0,0,0,0.7);">"${esc(d.exact_phrase || '')}"</td>
                  <td style="padding:8px 10px;border-bottom:1px solid rgba(0,0,0,0.05);font-family:monospace;font-size:11px;color:rgba(0,0,0,0.55);">${esc(d.source_location || '')}</td>
                  <td style="padding:8px 10px;border-bottom:1px solid rgba(0,0,0,0.05);color:rgba(0,0,0,0.65);">${esc(d.estimated_bom_correction || '')}</td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>
        </div>
      </div>
    </div>`;
}

function buildDoorScheduleCard(st) {
  const dsp = st._doorSchedule;
  if (!dsp) return '';
  const hw = dsp.hardware_summary || {};
  const acDoors = Array.isArray(dsp.access_control_doors) ? dsp.access_control_doors : [];
  const total = dsp.total_doors || 0;
  if (!dsp.schedule_found && total === 0) return '';

  return `
    <div class="info-card" id="door-schedule-card" style="border-left:3px solid #0EA5E9;margin-top:16px;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;cursor:pointer;" id="ds-toggle">
        <h3 class="info-card-title" style="margin:0;display:flex;align-items:center;gap:8px;">
          <span style="font-size:18px;">🚪</span> DOOR SCHEDULE PARSER
          <span style="padding:3px 10px;border-radius:10px;font-size:10px;font-weight:800;background:#0EA5E9;color:white;letter-spacing:0.5px;">${total} DOORS · ${acDoors.length} AC</span>
        </h3>
        <span style="font-size:11px;color:rgba(0,0,0,0.4);text-transform:uppercase;letter-spacing:1px;">&#9660; EXPAND</span>
      </div>
      <div id="ds-body" style="display:none;">
        <div style="display:flex;gap:10px;margin-bottom:14px;flex-wrap:wrap;">
          ${[
            ['Card Readers', hw.card_readers_from_schedule || 0, '#0EA5E9'],
            ['Electric Strikes', hw.electric_strikes || 0, '#10B981'],
            ['Mag Locks', hw.mag_locks || 0, '#8B5CF6'],
            ['REX Sensors', hw.rex_sensors || 0, '#F59E0B'],
            ['Door Contacts', hw.door_contacts || 0, '#EF4444'],
            ['Auto Operators', hw.auto_operators || 0, '#06B6D4'],
            ['Hold-Opens', hw.hold_opens || 0, '#D97706'],
            ['Delayed Egress', hw.delayed_egress || 0, '#DC2626'],
          ].map(([label, n, c]) => `
            <div style="flex:1;min-width:120px;padding:10px 14px;background:rgba(14,165,233,0.04);border-radius:8px;border-top:2px solid ${c};">
              <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.5px;color:rgba(0,0,0,0.5);">${label}</div>
              <div style="font-size:20px;font-weight:800;color:${c};">${n}</div>
            </div>
          `).join('')}
        </div>
        ${dsp.comparison_to_plans ? `
          <div style="padding:10px 14px;background:rgba(245,158,11,0.08);border-left:3px solid #F59E0B;border-radius:6px;margin-bottom:14px;font-size:13px;color:rgba(0,0,0,0.75);">
            <b>Plan cross-check:</b> ${esc(dsp.comparison_to_plans)}
          </div>
        ` : ''}
        <div style="font-size:11px;color:rgba(0,0,0,0.55);margin-bottom:6px;">Source: ${esc(dsp.schedule_source || 'Unknown')}</div>
        <div style="max-height:320px;overflow-y:auto;">
          <table style="width:100%;border-collapse:collapse;font-size:12px;">
            <thead><tr style="background:rgba(0,0,0,0.04);">
              <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">Door</th>
              <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">Location</th>
              <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">HW Set</th>
              <th style="text-align:left;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">ELV Components</th>
              <th style="text-align:center;padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.1);">AC</th>
            </tr></thead>
            <tbody>
              ${(Array.isArray(dsp.doors) ? dsp.doors : []).slice(0, 120).map(d => `<tr>
                <td style="padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.05);font-family:monospace;font-weight:700;">${esc(d.door_no || '')}</td>
                <td style="padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.05);">${esc(d.location || '')}</td>
                <td style="padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.05);font-family:monospace;">${esc(d.hardware_set || '')}</td>
                <td style="padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.05);color:rgba(0,0,0,0.7);">${Array.isArray(d.elv_components) ? d.elv_components.map(c => esc(c)).join(', ') : ''}</td>
                <td style="padding:6px 10px;border-bottom:1px solid rgba(0,0,0,0.05);text-align:center;">${d.access_controlled ? '<span style="color:#10B981;font-weight:800;">✓</span>' : '<span style="color:rgba(0,0,0,0.25);">—</span>'}</td>
              </tr>`).join('')}
            </tbody>
          </table>
        </div>
      </div>
    </div>`;
}

function buildKeynoteCard(st) {
  const ke = st._keynotes;
  if (!ke) return '';
  const gotchas = Array.isArray(ke.scope_gotchas) ? ke.scope_gotchas : [];
  const generalNotes = Array.isArray(ke.general_notes) ? ke.general_notes : [];
  const keynotes = Array.isArray(ke.keynotes) ? ke.keynotes : [];
  if (gotchas.length === 0 && generalNotes.length === 0 && keynotes.length === 0) return '';

  const critical = gotchas.filter(g => g.severity === 'critical');
  const color = critical.length > 0 ? '#EF4444' : '#0D9488';

  return `
    <div class="info-card" id="keynote-card" style="border-left:3px solid ${color};margin-top:16px;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;cursor:pointer;" id="kn-toggle">
        <h3 class="info-card-title" style="margin:0;display:flex;align-items:center;gap:8px;">
          <span style="font-size:18px;">🏷️</span> KEYNOTES &amp; GENERAL NOTES
          <span style="padding:3px 10px;border-radius:10px;font-size:10px;font-weight:800;background:${color};color:white;letter-spacing:0.5px;">${generalNotes.length + keynotes.length} NOTES</span>
          ${gotchas.length > 0 ? `<span style="font-size:12px;font-weight:700;color:${color};">${gotchas.length} scope gotcha${gotchas.length === 1 ? '' : 's'}</span>` : ''}
        </h3>
        <span style="font-size:11px;color:rgba(0,0,0,0.4);text-transform:uppercase;letter-spacing:1px;">&#9660; EXPAND</span>
      </div>
      <div id="kn-body" style="display:${critical.length > 0 ? 'block' : 'none'};">
        ${gotchas.length > 0 ? `
          <div style="margin-bottom:14px;">
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:${color};font-weight:800;margin-bottom:8px;">⚠ Scope Gotchas (${gotchas.length})</div>
            ${gotchas.map(g => {
              const sevColor = g.severity === 'critical' ? '#EF4444' : g.severity === 'warning' ? '#F59E0B' : '#10B981';
              return `<div style="padding:10px 14px;margin-bottom:8px;background:rgba(239,68,68,0.04);border-left:3px solid ${sevColor};border-radius:6px;">
                <div style="font-size:10px;text-transform:uppercase;font-weight:700;color:${sevColor};letter-spacing:0.5px;margin-bottom:4px;">${esc(g.sheet || '')} · ${esc(g.severity || 'info')}</div>
                <div style="font-size:13px;font-style:italic;color:rgba(0,0,0,0.8);margin-bottom:4px;">"${esc(g.quote || '')}"</div>
                <div style="font-size:12px;color:rgba(0,0,0,0.6);">${esc(g.why_gotcha || '')}</div>
              </div>`;
            }).join('')}
          </div>
        ` : ''}
        ${generalNotes.length > 0 ? `
          <details style="margin-bottom:10px;">
            <summary style="cursor:pointer;font-size:11px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);font-weight:700;">General Notes (${generalNotes.length})</summary>
            <div style="margin-top:8px;max-height:300px;overflow-y:auto;">
              ${generalNotes.map(n => `<div style="padding:8px 12px;border-bottom:1px solid rgba(0,0,0,0.06);font-size:12px;">
                <span style="font-family:monospace;font-weight:700;color:rgba(0,0,0,0.5);">${esc(n.source_sheet || '')} · #${esc(n.note_number || '')}</span>
                <span style="margin-left:8px;padding:2px 8px;border-radius:10px;font-size:10px;background:rgba(99,102,241,0.1);color:#6366F1;">${esc(n.category || '')}</span>
                <div style="margin-top:4px;color:rgba(0,0,0,0.75);">${esc(n.note_text || '')}</div>
                ${n.likely_bom_line_item && n.in_bom === false ? `<div style="margin-top:4px;font-size:11px;color:#EF4444;">⚠ Likely missing from BOM: ${esc(n.likely_bom_line_item)}</div>` : ''}
              </div>`).join('')}
            </div>
          </details>
        ` : ''}
        ${keynotes.length > 0 ? `
          <details>
            <summary style="cursor:pointer;font-size:11px;text-transform:uppercase;letter-spacing:1px;color:rgba(0,0,0,0.5);font-weight:700;">Per-Sheet Keynotes (${keynotes.length})</summary>
            <div style="margin-top:8px;max-height:300px;overflow-y:auto;">
              ${keynotes.map(k => `<div style="padding:8px 12px;border-bottom:1px solid rgba(0,0,0,0.06);font-size:12px;">
                <span style="font-family:monospace;font-weight:700;color:rgba(0,0,0,0.5);">${esc(k.source_sheet || '')} · KN#${esc(k.keynote_ref || '')}</span>
                ${k.our_scope === false ? `<span style="margin-left:8px;padding:2px 8px;border-radius:10px;font-size:10px;background:rgba(239,68,68,0.1);color:#EF4444;">NOT OUR SCOPE</span>` : ''}
                <div style="margin-top:4px;color:rgba(0,0,0,0.75);">${esc(k.note_text || '')}</div>
              </div>`).join('')}
            </div>
          </details>
        ` : ''}
      </div>
    </div>`;
}

function buildChangeOrderCard(st) {
  const cos = extractPotentialChangeOrders(st);
  if (cos.length === 0) return '';

  const fmt = n => '$' + (n || 0).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
  const sevBadge = s => {
    const colors = { critical: '#DC2626', high: '#EA580C', medium: '#D97706', low: '#65A30D' };
    return `<span style="display:inline-block;padding:3px 10px;border-radius:10px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:white;background:${colors[s] || colors.medium};">${esc(s)}</span>`;
  };
  const sevLabel = s => {
    const labels = { critical: 'Almost certain to occur — budget for this.', high: 'Highly likely — strong probability of occurring.', medium: 'Possible — depends on site conditions or owner decisions.', low: 'Low probability but worth documenting.' };
    return labels[s] || '';
  };

  const included = cos.filter(c => !st._excludedCOs.has(c.id));
  const totalValue = included.reduce((s, c) => s + c.estimatedCost, 0);
  const bySev = {};
  included.forEach(c => { bySev[c.severity] = (bySev[c.severity] || 0) + 1; });

  // Build individual detailed CO cards instead of a simple table
  let coCards = '';
  cos.forEach((c, idx) => {
    const excluded = st._excludedCOs.has(c.id);
    const sevColors = { critical: '#DC2626', high: '#EA580C', medium: '#D97706', low: '#65A30D' };
    const borderColor = sevColors[c.severity] || '#D97706';

    coCards += `
      <div class="co-detail-card" style="border:1px solid rgba(0,0,0,0.08);border-left:4px solid ${borderColor};margin-bottom:12px;padding:0;background:${excluded ? 'rgba(0,0,0,0.02)' : '#FFFFFF'};${excluded ? 'opacity:0.45;' : ''}">
        <!-- CO Header -->
        <div style="display:flex;align-items:center;justify-content:space-between;padding:14px 16px 10px 16px;border-bottom:1px solid rgba(0,0,0,0.04);">
          <div style="display:flex;align-items:center;gap:10px;">
            <input type="checkbox" class="co-include-cb" data-co-id="${esc(c.id)}" ${excluded ? '' : 'checked'} style="width:16px;height:16px;accent-color:#0D9488;cursor:pointer;">
            <span style="font-size:14px;font-weight:800;color:${borderColor};letter-spacing:1px;">${esc(c.id)}</span>
            ${sevBadge(c.severity)}
            <span style="font-size:11px;color:rgba(0,0,0,0.35);font-style:italic;">${esc(sevLabel(c.severity))}</span>
          </div>
          <div style="display:flex;align-items:center;gap:8px;">
            <span style="font-size:16px;font-weight:800;color:${c.estimatedCost > 0 ? borderColor : 'rgba(0,0,0,0.3)'};">${c.estimatedCost > 0 ? fmt(c.estimatedCost) : 'TBD'}</span>
            <button class="co-pdf-single" data-co-idx="${idx}" style="padding:5px 10px;border:1px solid rgba(234,88,12,0.25);background:rgba(234,88,12,0.04);color:#EA580C;cursor:pointer;font-size:10px;font-weight:700;letter-spacing:0.5px;display:flex;align-items:center;gap:4px;" title="Print this Change Order to PDF">
              <i data-lucide="printer" style="width:12px;height:12px;"></i> PDF
            </button>
          </div>
        </div>

        <!-- CO Body -->
        <div style="padding:14px 16px;">
          <!-- What -->
          <div style="margin-bottom:10px;">
            <div style="font-size:10px;font-weight:700;color:#EA580C;text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">What Is This Change Order?</div>
            <div style="font-size:13px;color:var(--text-primary);line-height:1.5;">${esc(c.description)}</div>
          </div>

          <!-- Why -->
          ${c.justification ? `
          <div style="margin-bottom:10px;">
            <div style="font-size:10px;font-weight:700;color:#EA580C;text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">Why This May Be Needed</div>
            <div style="font-size:12px;color:var(--text-primary);line-height:1.5;background:rgba(234,88,12,0.03);padding:8px 12px;border-radius:6px;border:1px solid rgba(234,88,12,0.08);">${esc(c.justification)}</div>
          </div>` : ''}

          <!-- Recommendation -->
          ${c.recommendation ? `
          <div style="margin-bottom:10px;">
            <div style="font-size:10px;font-weight:700;color:#0D9488;text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">Recommendation</div>
            <div style="font-size:12px;color:var(--text-primary);line-height:1.5;background:rgba(13,148,136,0.03);padding:8px 12px;border-radius:6px;border:1px solid rgba(13,148,136,0.08);">${esc(c.recommendation)}</div>
          </div>` : ''}

          <!-- Cost Breakdown if available -->
          ${c.costBreakdown ? `
          <div style="margin-bottom:10px;">
            <div style="font-size:10px;font-weight:700;color:#6366F1;text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">Cost Breakdown</div>
            <div style="font-size:12px;color:var(--text-primary);line-height:1.5;background:rgba(99,102,241,0.03);padding:8px 12px;border-radius:6px;border:1px solid rgba(99,102,241,0.08);">${esc(c.costBreakdown)}</div>
          </div>` : ''}

          <!-- Footer: source & category -->
          <div style="display:flex;gap:16px;align-items:center;margin-top:6px;padding-top:8px;border-top:1px solid rgba(0,0,0,0.04);">
            <span style="font-size:10px;color:var(--text-muted);"><strong>Source:</strong> ${esc(c.source)}</span>
            ${c.discipline ? `<span style="font-size:10px;color:var(--text-muted);"><strong>Discipline:</strong> ${esc(c.discipline)}</span>` : ''}
            ${c.contractRef ? `<span style="font-size:10px;color:var(--text-muted);"><strong>Ref:</strong> ${esc(c.contractRef)}</span>` : ''}
          </div>
        </div>
      </div>`;
  });

  return `
    <div style="border-top:1px solid rgba(0,0,0,0.06);margin:24px 0;"></div>
    <div class="info-card" id="change-orders-card" style="border-left:3px solid #EA580C;">
      <div style="display:flex;align-items:center;justify-content:space-between;cursor:pointer;" id="co-toggle">
        <h3 class="info-card-title" style="margin:0;">
          <i data-lucide="alert-triangle" style="width:16px;height:16px;"></i>
          POTENTIAL CHANGE ORDERS
          <span style="font-size:11px;font-weight:400;color:rgba(0,0,0,0.4);margin-left:8px;">(${cos.length} items | ${fmt(totalValue)} estimated exposure)</span>
        </h3>
        <span id="co-toggle-icon" style="font-size:14px;color:var(--text-muted);transition:transform 0.2s;padding:8px;">${st._changeOrdersOpen ? '▼' : '▶'}</span>
      </div>
      <div id="co-collapsible" style="display:${st._changeOrdersOpen ? 'block' : 'none'};margin-top:12px;">
        <p style="color:rgba(0,0,0,0.5);font-size:12px;margin-bottom:16px;line-height:1.5;">
          These are items <strong>NOT</strong> in the plans or specifications that may arise during construction. Each represents a legitimate change order risk — ambiguous scope, owner-requested additions, code requirements not addressed in contract documents, or site conditions that can't be known until construction begins. Items that ARE shown on the plans or in the specs are already included in your bid.
        </p>

        <!-- Severity Summary Bar -->
        <div style="display:flex;gap:10px;margin-bottom:18px;flex-wrap:wrap;align-items:center;padding:10px 14px;background:rgba(234,88,12,0.04);border:1px solid rgba(234,88,12,0.1);border-radius:8px;">
          ${Object.entries(bySev).map(([sev, count]) => `
            <div style="display:flex;align-items:center;gap:4px;">${sevBadge(sev)} <span style="font-size:12px;font-weight:600;">×${count}</span></div>
          `).join('')}
          <div style="margin-left:auto;font-size:16px;font-weight:800;color:#EA580C;">Total Exposure: ${fmt(totalValue)}</div>
        </div>

        <!-- Individual CO Detail Cards -->
        ${coCards}

        <!-- Actions -->
        <div style="display:flex;gap:8px;margin-top:16px;align-items:center;flex-wrap:wrap;">
          <button id="co-copy-btn" style="padding:8px 16px;border:1px solid rgba(234,88,12,0.3);background:rgba(234,88,12,0.06);color:#EA580C;cursor:pointer;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;display:flex;align-items:center;gap:6px;">
            <i data-lucide="clipboard-copy" style="width:14px;height:14px;"></i> Copy All to Clipboard
          </button>
          <button id="co-pdf-all-btn" style="padding:8px 16px;border:1px solid rgba(234,88,12,0.3);background:rgba(234,88,12,0.06);color:#EA580C;cursor:pointer;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;display:flex;align-items:center;gap:6px;">
            <i data-lucide="file-text" style="width:14px;height:14px;"></i> Print All to PDF
          </button>
          <span id="co-copy-status" style="font-size:11px;color:var(--accent-emerald);display:none;">Copied!</span>
        </div>
      </div>
    </div>`;
}

function _buildCOPdfHtml(co, projectName, preparedFor) {
  const fmt = n => '$' + (n || 0).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
  const sevColors = { critical: '#DC2626', high: '#EA580C', medium: '#D97706', low: '#65A30D' };
  const sevLabels = { critical: 'Almost certain to occur — budget for this.', high: 'Highly likely — strong probability of occurring.', medium: 'Possible — depends on site conditions or owner decisions.', low: 'Low probability but worth documenting.' };
  const date = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
  const bc = sevColors[co.severity] || '#D97706';
  // Escape all user/AI-controlled strings to prevent XSS in the popup window
  const e = s => esc(String(s || ''));

  return `<!DOCTYPE html><html><head><title>${e(co.id)} — ${e(projectName) || 'Project'}</title>
    <style>
      *{margin:0;padding:0;box-sizing:border-box}
      body{font-family:Arial,Helvetica,sans-serif;color:#1a1a2e;padding:40px;max-width:850px;margin:0 auto}
      @media print{body{padding:20px}button{display:none!important}}
      .section{margin-bottom:18px}
      .section-label{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1.5px;margin-bottom:6px;padding-bottom:4px;border-bottom:1px solid #eee}
      .section-body{font-size:13px;line-height:1.65;color:#333}
      .meta-row{display:flex;gap:24px;flex-wrap:wrap;font-size:12px;color:#555}
      .meta-item strong{color:#333}
    </style></head><body>
    <!-- Header -->
    <div style="border-bottom:3px solid ${bc};padding-bottom:16px;margin-bottom:28px;">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;">
        <div>
          <div style="font-size:11px;font-weight:700;color:${bc};text-transform:uppercase;letter-spacing:2px;margin-bottom:4px;">Potential Change Order</div>
          <h1 style="font-size:28px;font-weight:800;color:#1a1a2e;margin-bottom:6px;">${e(co.id)}</h1>
          <div style="font-size:15px;font-weight:600;color:#333;margin-bottom:2px;">${e(projectName) || 'Project'}</div>
          ${preparedFor ? `<div style="font-size:12px;color:#666;">Prepared for: ${e(preparedFor)}</div>` : ''}
          <div style="font-size:12px;color:#666;">Date: ${date}</div>
        </div>
        <div style="text-align:right;">
          <div style="font-size:32px;font-weight:900;color:${bc};">${co.estimatedCost > 0 ? fmt(co.estimatedCost) : 'TBD'}</div>
          <div style="margin-top:4px;">
            <span style="display:inline-block;padding:4px 12px;border-radius:12px;font-size:11px;font-weight:700;color:white;background:${bc};text-transform:uppercase;letter-spacing:1px;">${e(co.severity)}</span>
          </div>
          <div style="font-size:10px;color:#888;margin-top:4px;font-style:italic;">${sevLabels[co.severity] || ''}</div>
        </div>
      </div>
    </div>

    <!-- What -->
    <div class="section">
      <div class="section-label" style="color:${bc};">What Is This Change Order?</div>
      <div class="section-body">${e(co.description)}</div>
    </div>

    <!-- Why -->
    ${co.justification ? `<div class="section">
      <div class="section-label" style="color:${bc};">Why This May Be Needed</div>
      <div class="section-body" style="background:#FFF8F3;padding:12px 16px;border-radius:6px;border-left:3px solid ${bc};">${e(co.justification)}</div>
    </div>` : ''}

    <!-- Recommendation -->
    ${co.recommendation ? `<div class="section">
      <div class="section-label" style="color:#0D9488;">Recommendation</div>
      <div class="section-body" style="background:#F0FDFA;padding:12px 16px;border-radius:6px;border-left:3px solid #0D9488;">${e(co.recommendation)}</div>
    </div>` : ''}

    <!-- Cost Breakdown -->
    ${co.costBreakdown ? `<div class="section">
      <div class="section-label" style="color:#6366F1;">Cost Breakdown</div>
      <div class="section-body" style="background:#F5F3FF;padding:12px 16px;border-radius:6px;border-left:3px solid #6366F1;">${e(co.costBreakdown)}</div>
    </div>` : ''}

    <!-- Metadata -->
    <div style="margin-top:24px;padding-top:16px;border-top:2px solid #eee;">
      <div class="meta-row">
        <div class="meta-item"><strong>Source:</strong> ${e(co.source)}</div>
        ${co.discipline ? `<div class="meta-item"><strong>Discipline:</strong> ${e(co.discipline)}</div>` : ''}
        ${co.contractRef ? `<div class="meta-item"><strong>Contract Reference:</strong> ${e(co.contractRef)}</div>` : ''}
        <div class="meta-item"><strong>Severity:</strong> ${e(co.severity).toUpperCase()}</div>
        <div class="meta-item"><strong>Estimated Impact:</strong> ${co.estimatedCost > 0 ? fmt(co.estimatedCost) : 'To Be Determined'}</div>
      </div>
    </div>

    <!-- Footer -->
    <div style="margin-top:32px;padding-top:12px;border-top:1px solid #ddd;font-size:10px;color:#999;text-align:center;">
      Generated by SmartPlans AI — 3D Technology Services Inc. | 3D CONFIDENTIAL
    </div>
    <script>window.onload=function(){window.print();}</script>
  </body></html>`;
}

function bindChangeOrderEvents(container) {
  const toggle = document.getElementById('co-toggle');
  if (toggle) {
    toggle.addEventListener('click', () => {
      state._changeOrdersOpen = !state._changeOrdersOpen;
      const body = document.getElementById('co-collapsible');
      const icon = document.getElementById('co-toggle-icon');
      if (body) body.style.display = state._changeOrdersOpen ? 'block' : 'none';
      if (icon) icon.textContent = state._changeOrdersOpen ? '▼' : '▶';
    });
  }

  // Checkboxes to include/exclude individual COs
  document.querySelectorAll('.co-include-cb').forEach(cb => {
    cb.addEventListener('change', () => {
      const coId = cb.dataset.coId;
      if (cb.checked) state._excludedCOs.delete(coId);
      else state._excludedCOs.add(coId);
      renderStep7(container);
    });
  });

  // Individual PDF button per change order
  document.querySelectorAll('.co-pdf-single').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const idx = parseInt(btn.dataset.coIdx, 10);
      const cos = extractPotentialChangeOrders(state);
      const co = cos[idx];
      if (!co) return;
      const html = _buildCOPdfHtml(co, state.projectName, state.preparedFor);
      const win = window.open('', '_blank');
      if (win) { win.document.write(html); win.document.close(); }
    });
  });

  // Copy All to Clipboard
  const copyBtn = document.getElementById('co-copy-btn');
  if (copyBtn) {
    copyBtn.addEventListener('click', () => {
      const cos = extractPotentialChangeOrders(state).filter(c => !state._excludedCOs.has(c.id));
      const fmt = n => '$' + (n || 0).toLocaleString('en-US');
      let text = `POTENTIAL CHANGE ORDERS — ${state.projectName || 'Project'}\n`;
      text += '═'.repeat(90) + '\n\n';
      cos.forEach(c => {
        text += `${c.id}  |  ${c.severity.toUpperCase()}  |  ${c.estimatedCost > 0 ? fmt(c.estimatedCost) : 'TBD'}\n`;
        text += '─'.repeat(60) + '\n';
        text += `WHAT: ${c.description}\n`;
        if (c.justification) text += `WHY:  ${c.justification}\n`;
        if (c.recommendation) text += `REC:  ${c.recommendation}\n`;
        if (c.costBreakdown) text += `COST: ${c.costBreakdown}\n`;
        text += `Source: ${c.source}`;
        if (c.discipline) text += `  |  Discipline: ${c.discipline}`;
        if (c.contractRef) text += `  |  Ref: ${c.contractRef}`;
        text += '\n\n';
      });
      const total = cos.reduce((s, c) => s + c.estimatedCost, 0);
      text += '═'.repeat(90) + '\n';
      text += `TOTAL ESTIMATED EXPOSURE: ${fmt(total)} (${cos.length} items)\n`;

      navigator.clipboard.writeText(text).then(() => {
        const status = document.getElementById('co-copy-status');
        if (status) { status.style.display = 'inline'; setTimeout(() => { status.style.display = 'none'; }, 2000); }
      });
    });
  }

  // Print All COs to PDF
  const pdfAllBtn = document.getElementById('co-pdf-all-btn');
  if (pdfAllBtn) {
    pdfAllBtn.addEventListener('click', () => {
      const cos = extractPotentialChangeOrders(state).filter(c => !state._excludedCOs.has(c.id));
      const fmt = n => '$' + (n || 0).toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 });
      const total = cos.reduce((s, c) => s + c.estimatedCost, 0);
      const sevColors = { critical: '#DC2626', high: '#EA580C', medium: '#D97706', low: '#65A30D' };
      const sevLabels = { critical: 'Almost certain to occur — budget for this.', high: 'Highly likely — strong probability.', medium: 'Possible — depends on conditions.', low: 'Low probability but documented.' };
      const date = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

      const e = s => esc(String(s || ''));
      let coSections = '';
      cos.forEach((c, i) => {
        const bc = sevColors[c.severity] || '#D97706';
        coSections += `
          ${i > 0 ? '<div style="page-break-before:auto;border-top:2px solid #eee;margin:28px 0 20px 0;"></div>' : ''}
          <div style="margin-bottom:24px;">
            <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;">
              <div style="display:flex;align-items:center;gap:10px;">
                <span style="font-size:16px;font-weight:800;color:${bc};">${e(c.id)}</span>
                <span style="display:inline-block;padding:3px 10px;border-radius:10px;font-size:10px;font-weight:700;color:white;background:${bc};text-transform:uppercase;">${e(c.severity)}</span>
                <span style="font-size:10px;color:#888;font-style:italic;">${sevLabels[c.severity] || ''}</span>
              </div>
              <span style="font-size:18px;font-weight:800;color:${bc};">${c.estimatedCost > 0 ? fmt(c.estimatedCost) : 'TBD'}</span>
            </div>
            <div style="margin-bottom:8px;">
              <div style="font-size:10px;font-weight:700;color:${bc};text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">What Is This Change Order?</div>
              <div style="font-size:12px;line-height:1.55;color:#333;">${e(c.description)}</div>
            </div>
            ${c.justification ? `<div style="margin-bottom:8px;">
              <div style="font-size:10px;font-weight:700;color:${bc};text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">Why This May Be Needed</div>
              <div style="font-size:12px;line-height:1.55;color:#333;background:#FFF8F3;padding:8px 12px;border-radius:4px;border-left:3px solid ${bc};">${e(c.justification)}</div>
            </div>` : ''}
            ${c.recommendation ? `<div style="margin-bottom:8px;">
              <div style="font-size:10px;font-weight:700;color:#0D9488;text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">Recommendation</div>
              <div style="font-size:12px;line-height:1.55;color:#333;background:#F0FDFA;padding:8px 12px;border-radius:4px;border-left:3px solid #0D9488;">${e(c.recommendation)}</div>
            </div>` : ''}
            ${c.costBreakdown ? `<div style="margin-bottom:8px;">
              <div style="font-size:10px;font-weight:700;color:#6366F1;text-transform:uppercase;letter-spacing:1px;margin-bottom:3px;">Cost Breakdown</div>
              <div style="font-size:12px;line-height:1.55;color:#333;background:#F5F3FF;padding:8px 12px;border-radius:4px;border-left:3px solid #6366F1;">${e(c.costBreakdown)}</div>
            </div>` : ''}
            <div style="font-size:10px;color:#888;margin-top:6px;">Source: ${e(c.source)}${c.discipline ? ' | Discipline: ' + e(c.discipline) : ''}${c.contractRef ? ' | Ref: ' + e(c.contractRef) : ''}</div>
          </div>`;
      });

      const html = `<!DOCTYPE html><html><head><title>Potential Change Orders — ${e(state.projectName) || 'Project'}</title>
        <style>
          *{margin:0;padding:0;box-sizing:border-box}
          body{font-family:Arial,Helvetica,sans-serif;color:#1a1a2e;padding:40px;max-width:900px;margin:0 auto}
          @media print{body{padding:20px}}
        </style></head><body>
        <div style="display:flex;align-items:flex-start;justify-content:space-between;border-bottom:3px solid #EA580C;padding-bottom:16px;margin-bottom:28px;">
          <div>
            <h1 style="font-size:22px;color:#EA580C;margin-bottom:4px;">Potential Change Orders</h1>
            <div style="font-size:15px;font-weight:600;">${e(state.projectName) || 'Project'}</div>
            <div style="font-size:12px;color:#666;">${state.preparedFor ? 'Prepared for: ' + e(state.preparedFor) + ' | ' : ''}${date}</div>
          </div>
          <div style="text-align:right;">
            <div style="font-size:28px;font-weight:900;color:#EA580C;">${fmt(total)}</div>
            <div style="font-size:11px;color:#666;">${cos.length} items — total estimated exposure</div>
          </div>
        </div>
        ${coSections}
        <div style="margin-top:32px;padding-top:12px;border-top:1px solid #ddd;font-size:10px;color:#999;text-align:center;">
          Generated by SmartPlans AI — 3D Technology Services Inc. | 3D CONFIDENTIAL
        </div>
        <script>window.onload=function(){window.print();}</script>
      </body></html>`;

      const win = window.open('', '_blank');
      if (win) { win.document.write(html); win.document.close(); }
    });
  }
}

// BID PHASES / ALTERNATES
function getBidPhaseBOM() { if (!state.aiAnalysis) return { categories: [], grandTotal: 0 }; const bom = getFilteredBOM(state.aiAnalysis, state.disciplines); const overrides = state.supplierPriceOverrides || {}; for (const [key, ov] of Object.entries(overrides)) { const [ci, ii] = key.split('-').map(Number); if (bom.categories[ci] && bom.categories[ci].items[ii]) { const it = bom.categories[ci].items[ii]; if (ov.qty != null) it.qty = ov.qty; it.unitCost = ov.unitCost; it.extCost = Math.round(it.qty * ov.unitCost * 100) / 100; } } if (Object.keys(overrides).length > 0) { bom.grandTotal = 0; for (const cat of bom.categories) { cat.subtotal = cat.items.reduce((s, it) => s + it.extCost, 0); cat.subtotal = Math.round(cat.subtotal * 100) / 100; bom.grandTotal += cat.subtotal; } bom.grandTotal = Math.round(bom.grandTotal * 100) / 100; } return bom; }
function getPhaseTotal(phase, bom) { if (phase.type === 'base') { const ae = new Set(); state.bidPhases.forEach(p => { if (p.id !== 'base') p.categoryIndices.forEach(ci => ae.add(ci)); }); let t = 0; bom.categories.forEach((cat, ci) => { if (!ae.has(ci)) t += cat.subtotal; }); return Math.round(t * 100) / 100; } let t = 0; phase.categoryIndices.forEach(ci => { if (bom.categories[ci]) t += bom.categories[ci].subtotal; }); return Math.round(t * 100) / 100; }
function getBaseBidCategoryIndices(bom) { const ae = new Set(); state.bidPhases.forEach(p => { if (p.id !== 'base') p.categoryIndices.forEach(ci => ae.add(ci)); }); const idx = []; bom.categories.forEach((_, ci) => { if (!ae.has(ci)) idx.push(ci); }); return idx; }
function buildBidPhasesCard(st) { if (!st.aiAnalysis) return ''; const bom = getBidPhaseBOM(); if (bom.categories.length === 0) return ''; const _fmt = (v) => { const abs = Math.abs(v); const str = '$' + abs.toLocaleString('en-US', {minimumFractionDigits:0,maximumFractionDigits:0}); return v < 0 ? '(' + str + ')' : str; }; const ptm = { base: {label:'Base Bid',bc:'bid-phase-badge--base'}, add: {label:'Add Alternate',bc:'bid-phase-badge--add'}, deduct: {label:'Deduct Alt',bc:'bid-phase-badge--deduct'}, optional: {label:'Optional',bc:'bid-phase-badge--optional'} }; let pr='',sr='',rt=0; st.bidPhases.forEach((phase, pi) => { const m = ptm[phase.type]||ptm.optional; const tot = getPhaseTotal(phase,bom); const dt = phase.type==='deduct' ? -Math.abs(tot) : tot; if (phase.includeInProposal) rt += dt; let ac = phase.type==='base' ? getBaseBidCategoryIndices(bom) : phase.categoryIndices; const cn = ac.map(ci => bom.categories[ci] ? esc(bom.categories[ci].name) : '').filter(Boolean); let cah=''; if (phase.type!=='base') { const avail=[]; bom.categories.forEach((cat,ci) => { const at = st.bidPhases.find(p => p.id!=='base' && p.id!==phase.id && p.categoryIndices.includes(ci)); if (!at) avail.push({ci,name:cat.name,chk:phase.categoryIndices.includes(ci)}); else if (phase.categoryIndices.includes(ci)) avail.push({ci,name:cat.name,chk:true}); }); cah = '<div style="margin-top:8px;display:flex;flex-wrap:wrap;gap:4px;">' + avail.map(a => '<label class="bid-phase-cat-chip' + (a.chk?' bid-phase-cat-chip--active':'') + '" style="cursor:pointer;"><input type="checkbox" ' + (a.chk?'checked ':'') + 'style="display:none;" data-bid-phase-cat="' + phase.id + '" data-cat-idx="' + a.ci + '">' + esc(a.name) + '</label>').join('') + (avail.length===0?'<span style="font-size:11px;color:var(--text-muted);font-style:italic;">All categories assigned to other phases</span>':'') + '</div>'; } pr += '<div class="bid-phase-row" data-phase-idx="'+pi+'" style="padding:14px 16px;border:1px solid rgba(0,0,0,0.06);margin-bottom:8px;background:var(--bg-surface-2);"><div style="display:flex;align-items:center;justify-content:space-between;gap:8px;flex-wrap:wrap;"><div style="display:flex;align-items:center;gap:8px;flex:1;min-width:0;"><span class="bid-phase-badge '+m.bc+'">'+m.label+'</span>' + (phase.type==='base' ? '<span style="font-weight:600;font-size:13px;color:var(--text-primary);">'+esc(phase.name)+'</span>' : '<input type="text" class="bid-phase-name-input" data-phase-id="'+phase.id+'" value="'+esc(phase.name)+'" style="flex:1;padding:4px 8px;border:1px solid rgba(0,0,0,0.08);background:transparent;font-size:13px;font-weight:600;color:var(--text-primary);min-width:120px;outline:none;font-family:var(--font-sans);" />') + '</div><div style="display:flex;align-items:center;gap:8px;"><span style="font-size:14px;font-weight:700;color:'+(phase.type==='deduct'?'#D97706':'var(--accent-teal)')+';">'+_fmt(dt)+'</span><label style="display:flex;align-items:center;gap:4px;cursor:pointer;font-size:11px;color:var(--text-muted);" title="Include in Proposal"><input type="checkbox" '+(phase.includeInProposal?'checked ':'')+' data-bid-phase-proposal="'+phase.id+'" style="accent-color:#0D9488;">Proposal</label>' + (phase.type!=='base' ? '<button data-bid-phase-remove="'+phase.id+'" title="Remove phase" style="background:none;border:1px solid rgba(225,29,72,0.2);color:#E11D48;cursor:pointer;font-size:12px;padding:2px 6px;line-height:1;">x</button>' : '') + '</div></div><div style="margin-top:6px;font-size:11px;color:var(--text-muted);">' + (cn.length>0 ? cn.join(', ') : '<em>No categories assigned</em>') + '</div>' + cah + '</div>'; sr += '<tr style="border-bottom:1px solid rgba(0,0,0,0.04);"><td style="padding:6px 10px;font-size:12px;color:var(--text-primary);">'+esc(phase.name)+'</td><td style="padding:6px 10px;font-size:11px;"><span class="bid-phase-badge '+m.bc+'" style="font-size:10px;padding:2px 6px;">'+m.label+'</span></td><td style="padding:6px 10px;font-size:12px;color:var(--text-muted);max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">'+(cn.join(', ')||'—')+'</td><td style="padding:6px 10px;font-size:13px;font-weight:600;text-align:right;color:'+(phase.type==='deduct'?'#D97706':'var(--text-primary)')+';">'+_fmt(dt)+'</td><td style="padding:6px 10px;text-align:center;font-size:12px;">'+(phase.includeInProposal?'✓':'—')+'</td></tr>'; }); const st2 = '<div style="margin-top:16px;overflow-x:auto;"><table style="width:100%;border-collapse:collapse;font-size:12px;"><thead><tr style="background:rgba(13,148,136,0.06);"><th style="padding:8px 10px;text-align:left;font-size:11px;color:var(--accent-teal);font-weight:700;border-bottom:2px solid rgba(13,148,136,0.15);">Phase</th><th style="padding:8px 10px;text-align:left;font-size:11px;color:var(--accent-teal);font-weight:700;border-bottom:2px solid rgba(13,148,136,0.15);">Type</th><th style="padding:8px 10px;text-align:left;font-size:11px;color:var(--accent-teal);font-weight:700;border-bottom:2px solid rgba(13,148,136,0.15);">Categories</th><th style="padding:8px 10px;text-align:right;font-size:11px;color:var(--accent-teal);font-weight:700;border-bottom:2px solid rgba(13,148,136,0.15);">Amount</th><th style="padding:8px 10px;text-align:center;font-size:11px;color:var(--accent-teal);font-weight:700;border-bottom:2px solid rgba(13,148,136,0.15);">Proposal</th></tr></thead><tbody>'+sr+'<tr style="background:rgba(13,148,136,0.08);"><td colspan="3" style="padding:8px 10px;font-size:13px;font-weight:700;color:var(--text-primary);text-align:right;">Total if all accepted</td><td style="padding:8px 10px;font-size:14px;font-weight:700;color:var(--accent-teal);text-align:right;">'+_fmt(rt)+'</td><td></td></tr></tbody></table></div>'; return '<div style="border-top:1px solid rgba(0,0,0,0.06);margin:24px 0;"></div><div class="info-card" style="margin-bottom:22px;border:1px solid rgba(13,148,136,0.15);background:#FFFFFF;"><div style="display:flex;align-items:center;justify-content:space-between;padding-left:8px;cursor:pointer;" id="bid-phases-toggle"><div class="info-card-title" style="margin-bottom:0;"><i data-lucide="layers" style="width:16px;height:16px;"></i> Bid Phases &amp; Alternates</div><span id="bid-phases-toggle-icon" style="font-size:14px;color:var(--text-muted);transition:transform 0.2s;padding:8px;">'+(st._bidPhasesOpen?'▼':'▶')+'</span></div><div id="bid-phases-collapsible" style="display:'+(st._bidPhasesOpen?'block':'none')+';margin-top:12px;"><div class="info-card-body" style="margin-bottom:12px;">Structure your bid with base and alternate pricing. Assign BOM categories to each phase — unassigned categories stay in the Base Bid.</div>'+pr+'<div style="display:flex;gap:8px;margin-top:10px;flex-wrap:wrap;"><button id="bid-phase-add-add" style="padding:6px 14px;border:1px solid rgba(16,185,129,0.3);background:rgba(16,185,129,0.04);color:#059669;cursor:pointer;font-size:12px;font-weight:600;font-family:var(--font-sans);">+ Add Alternate</button><button id="bid-phase-add-deduct" style="padding:6px 14px;border:1px solid rgba(217,119,6,0.3);background:rgba(217,119,6,0.04);color:#D97706;cursor:pointer;font-size:12px;font-weight:600;font-family:var(--font-sans);">+ Deduct Alternate</button><button id="bid-phase-add-optional" style="padding:6px 14px;border:1px solid rgba(0,0,0,0.1);background:rgba(0,0,0,0.02);color:var(--text-muted);cursor:pointer;font-size:12px;font-weight:600;font-family:var(--font-sans);">+ Optional Phase</button></div>'+st2+'</div></div>'; }
function bindBidPhasesEvents(container) { const toggle = document.getElementById('bid-phases-toggle'); if (toggle) { toggle.addEventListener('click', () => { state._bidPhasesOpen = !state._bidPhasesOpen; const body = document.getElementById('bid-phases-collapsible'); const icon = document.getElementById('bid-phases-toggle-icon'); if (body) body.style.display = state._bidPhasesOpen ? 'block' : 'none'; if (icon) icon.textContent = state._bidPhasesOpen ? '▼' : '▶'; }); } const ah = {'bid-phase-add-add':'add','bid-phase-add-deduct':'deduct','bid-phase-add-optional':'optional'}; for (const [bi,ty] of Object.entries(ah)) { const btn = document.getElementById(bi); if (btn) btn.addEventListener('click', () => { state._bidPhaseCounter++; const n = state.bidPhases.filter(p=>p.type===ty).length+1; const lb = {add:`Add Alternate #${n}`,deduct:`Deduct Alternate #${n}`,optional:`Optional Phase #${n}`}; state.bidPhases.push({id:`phase-${Date.now()}-${state._bidPhaseCounter}`,name:lb[ty],type:ty,categoryIndices:[],includeInProposal:ty!=='optional'}); state._bidPhasesOpen=true; renderStep7(container); }); } document.querySelectorAll('[data-bid-phase-remove]').forEach(b => { b.addEventListener('click', e => { e.stopPropagation(); state.bidPhases = state.bidPhases.filter(p => p.id !== b.dataset.bidPhaseRemove); renderStep7(container); }); }); document.querySelectorAll('.bid-phase-name-input').forEach(inp => { inp.addEventListener('change', () => { const ph = state.bidPhases.find(p => p.id === inp.dataset.phaseId); if (ph) ph.name = inp.value.trim() || ph.name; }); }); document.querySelectorAll('[data-bid-phase-proposal]').forEach(cb => { cb.addEventListener('change', () => { const ph = state.bidPhases.find(p => p.id === cb.dataset.bidPhaseProposal); if (ph) { ph.includeInProposal = cb.checked; renderStep7(container); } }); }); document.querySelectorAll('[data-bid-phase-cat]').forEach(cb => { cb.addEventListener('change', () => { const pid = cb.dataset.bidPhaseCat; const ci = parseInt(cb.dataset.catIdx); const ph = state.bidPhases.find(p => p.id === pid); if (!ph) return; if (cb.checked) { state.bidPhases.forEach(p => { if (p.id!=='base' && p.id!==pid) p.categoryIndices = p.categoryIndices.filter(c=>c!==ci); }); if (!ph.categoryIndices.includes(ci)) ph.categoryIndices.push(ci); } else { ph.categoryIndices = ph.categoryIndices.filter(c=>c!==ci); } renderStep7(container); }); }); }

// LOW-2 fix: Duplicate beforeunload listener removed — the more comprehensive
// version inside DOMContentLoaded (line ~12764) checks legendFiles and analyzing state too.

// ═══════════════════════════════════════════════════════════════
// ERROR MONITORING — Log unhandled errors to /api/health
// ═══════════════════════════════════════════════════════════════

window.addEventListener('error', (event) => {
  try {
    fetch('/api/health', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        type: 'js_error',
        message: event.message,
        filename: event.filename,
        line: event.lineno,
        col: event.colno,
        stack: event.error?.stack?.substring(0, 1000),
        url: location.href,
        timestamp: new Date().toISOString(),
      }),
    }).catch((fetchErr) => { console.warn('Error reporting fetch failed:', fetchErr); }); // Best-effort, don't recurse
  } catch (e) { console.warn('Error handler failed:', e); }
});

window.addEventListener('unhandledrejection', (event) => {
  try {
    fetch('/api/health', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        type: 'promise_rejection',
        message: String(event.reason),
        stack: event.reason?.stack?.substring(0, 1000),
        url: location.href,
        timestamp: new Date().toISOString(),
      }),
    }).catch((fetchErr) => { console.warn('Rejection reporting fetch failed:', fetchErr); });
  } catch (e) { console.warn('Rejection handler failed:', e); }
});

// ═══════════════════════════════════════════════════════════════
// PDF PAGE EXTRACTOR TOOL
// ═══════════════════════════════════════════════════════════════

function openPdfPageTool() {
  // Remove existing modal if any
  document.querySelector('.pdf-tool-overlay')?.remove();

  const overlay = document.createElement('div');
  overlay.className = 'pdf-tool-overlay';
  overlay.innerHTML = `
    <div class="pdf-tool-modal">
      <div class="pdf-tool-header">
        <h3>PDF Page Extractor</h3>
        <button class="pdf-tool-close" data-action="close-pdf-tool">&times;</button>
      </div>
      <div class="pdf-tool-body">
        <div class="pdf-tool-section" id="pdfToolUpload">
          <label>1. Select a PDF</label>
          <p class="hint">Upload a plan set or specification document to extract specific pages from.</p>
          <div class="pdf-tool-drop" id="pdfToolDrop">
            <input type="file" accept=".pdf" id="pdfToolFileInput">
            <div class="icon">📄</div>
            <div class="text">Drop a PDF here or click to browse</div>
          </div>
        </div>
        <div id="pdfToolLoaded" style="display:none;">
          <div class="pdf-tool-filename" id="pdfToolFileInfo">
            <span class="name"></span>
            <span class="meta"></span>
          </div>
          <div class="pdf-tool-section">
            <label>2. Pages to Keep</label>
            <p class="hint">Enter page numbers or ranges. Examples: "1-10" or "1, 5, 8-12, 15" or "88-109"</p>
            <input type="text" class="pdf-tool-input" id="pdfToolPages" placeholder="e.g. 1-10, 15, 20-25">
          </div>
          <div class="pdf-tool-section">
            <label>3. Output File Name</label>
            <p class="hint">Name for the extracted PDF. It will be downloaded to your browser.</p>
            <input type="text" class="pdf-tool-output-name" id="pdfToolOutputName" placeholder="e.g. Electrical Pages.pdf">
          </div>
          <div id="pdfToolPreview"></div>
          <div id="pdfToolStatus"></div>
        </div>
      </div>
      <div class="pdf-tool-actions">
        <button class="pdf-tool-btn" data-action="close-pdf-tool">Cancel</button>
        <button class="pdf-tool-btn pdf-tool-btn--primary" id="pdfToolExtractBtn" disabled>Extract & Download</button>
      </div>
    </div>
  `;

  document.body.appendChild(overlay);

  // Close on overlay click or close button
  overlay.addEventListener('click', (e) => {
    if (e.target === overlay || e.target.closest('[data-action="close-pdf-tool"]')) {
      overlay.remove();
    }
  });

  // Close on Escape
  const escHandler = (e) => { if (e.key === 'Escape') { overlay.remove(); document.removeEventListener('keydown', escHandler); } };
  document.addEventListener('keydown', escHandler);

  // State
  let loadedPdfBytes = null;
  let loadedPdfDoc = null;
  let loadedFileName = '';

  const drop = document.getElementById('pdfToolDrop');
  const fileInput = document.getElementById('pdfToolFileInput');
  const pagesInput = document.getElementById('pdfToolPages');
  const outputNameInput = document.getElementById('pdfToolOutputName');
  const extractBtn = document.getElementById('pdfToolExtractBtn');

  // Drag & drop
  drop.addEventListener('dragover', (e) => { e.preventDefault(); drop.classList.add('drag-over'); });
  drop.addEventListener('dragleave', () => drop.classList.remove('drag-over'));
  drop.addEventListener('drop', (e) => { e.preventDefault(); drop.classList.remove('drag-over'); if (e.dataTransfer.files[0]) loadPdf(e.dataTransfer.files[0]); });
  fileInput.addEventListener('change', (e) => { if (e.target.files[0]) loadPdf(e.target.files[0]); });

  async function loadPdf(file) {
    if (!file.name.toLowerCase().endsWith('.pdf')) {
      showStatus('Please select a PDF file.', true);
      return;
    }
    try {
      loadedFileName = file.name;
      loadedPdfBytes = await file.arrayBuffer();

      // Use pdf-lib to count pages
      if (typeof PDFLib === 'undefined') {
        showStatus('PDF library not loaded. Please refresh the page.', true);
        return;
      }
      loadedPdfDoc = await PDFLib.PDFDocument.load(loadedPdfBytes, { ignoreEncryption: true });
      const pageCount = loadedPdfDoc.getPageCount();

      // Show loaded state
      document.getElementById('pdfToolUpload').style.display = 'none';
      const loaded = document.getElementById('pdfToolLoaded');
      loaded.style.display = 'block';

      const fileInfo = document.getElementById('pdfToolFileInfo');
      fileInfo.querySelector('.name').textContent = file.name;
      fileInfo.querySelector('.meta').textContent = `${pageCount} pages  ·  ${formatFileSize(file.size)}`;

      // Default output name
      const baseName = file.name.replace(/\.pdf$/i, '');
      outputNameInput.value = baseName + ' - extracted.pdf';

      // Auto-focus pages input
      pagesInput.focus();
    } catch (err) {
      showStatus('Failed to load PDF: ' + err.message, true);
    }
  }

  // Parse page ranges like "1-10, 15, 20-25"
  function parsePageRanges(input, maxPages) {
    const pages = new Set();
    const parts = input.split(',').map(s => s.trim()).filter(Boolean);
    for (const part of parts) {
      const rangeMatch = part.match(/^(\d+)\s*[-–]\s*(\d+)$/);
      if (rangeMatch) {
        const start = parseInt(rangeMatch[1], 10);
        const end = parseInt(rangeMatch[2], 10);
        if (start < 1 || end > maxPages || start > end) return null;
        for (let i = start; i <= end; i++) pages.add(i);
      } else if (/^\d+$/.test(part)) {
        const p = parseInt(part, 10);
        if (p < 1 || p > maxPages) return null;
        pages.add(p);
      } else {
        return null;
      }
    }
    return Array.from(pages).sort((a, b) => a - b);
  }

  // Update preview when pages input changes
  pagesInput?.addEventListener('input', () => {
    if (!loadedPdfDoc) return;
    const totalPages = loadedPdfDoc.getPageCount();
    const text = pagesInput.value.trim();
    const preview = document.getElementById('pdfToolPreview');

    if (!text) {
      preview.innerHTML = '';
      extractBtn.disabled = true;
      return;
    }

    const kept = parsePageRanges(text, totalPages);
    if (!kept || kept.length === 0) {
      preview.innerHTML = `<div class="pdf-tool-status error">Invalid page range. Use numbers 1-${totalPages}. Examples: "1-10" or "1, 5, 8-12"</div>`;
      extractBtn.disabled = true;
      return;
    }

    const keptSet = new Set(kept);
    const removed = totalPages - kept.length;

    let tableRows = '';
    for (let i = 1; i <= totalPages; i++) {
      const isKept = keptSet.has(i);
      tableRows += `<tr class="${isKept ? 'kept' : 'removed'}"><td>${i}</td><td>${isKept ? '✓ Keep' : '✕ Remove'}</td></tr>`;
    }

    preview.innerHTML = `
      <div class="pdf-tool-info">
        <strong>${kept.length}</strong> pages kept &nbsp;·&nbsp; <strong>${removed}</strong> pages removed &nbsp;·&nbsp; from ${totalPages} total
      </div>
      <div class="pdf-tool-preview">
        <table>
          <thead><tr><th>Page</th><th>Action</th></tr></thead>
          <tbody>${tableRows}</tbody>
        </table>
      </div>
    `;
    extractBtn.disabled = false;
  });

  // Extract button
  extractBtn?.addEventListener('click', async () => {
    if (!loadedPdfDoc) return;
    const totalPages = loadedPdfDoc.getPageCount();
    const kept = parsePageRanges(pagesInput.value.trim(), totalPages);
    if (!kept || kept.length === 0) return;

    extractBtn.disabled = true;
    extractBtn.textContent = 'Extracting...';

    try {
      // Create new PDF with only the kept pages
      const newPdf = await PDFLib.PDFDocument.create();
      const indices = kept.map(p => p - 1); // Convert to 0-based
      const copiedPages = await newPdf.copyPages(loadedPdfDoc, indices);
      copiedPages.forEach(page => newPdf.addPage(page));

      const pdfBytes = await newPdf.save();
      const blob = new Blob([pdfBytes], { type: 'application/pdf' });

      // Download
      let outputName = outputNameInput.value.trim() || 'extracted.pdf';
      if (!outputName.toLowerCase().endsWith('.pdf')) outputName += '.pdf';

      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = outputName;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      showStatus(`Saved "${outputName}" — ${kept.length} pages extracted from ${totalPages} total.`, false);
      extractBtn.textContent = 'Extract & Download';
      extractBtn.disabled = false;

      // Also offer to load into current step's file list
      const fileObj = { name: outputName, size: blob.size, type: 'application/pdf', rawFile: new File([blob], outputName, { type: 'application/pdf' }) };

      const statusEl = document.getElementById('pdfToolStatus');
      if (statusEl && !statusEl.querySelector('.pdf-tool-add-btns')) {
        const addBtns = document.createElement('div');
        addBtns.className = 'pdf-tool-add-btns';
        addBtns.style.cssText = 'display:flex;gap:8px;margin-top:10px;';
        addBtns.innerHTML = `
          <button class="pdf-tool-btn" id="pdfToolAddToPlans">+ Add to Floor Plans</button>
          <button class="pdf-tool-btn" id="pdfToolAddToSpecs">+ Add to Specifications</button>
          <button class="pdf-tool-btn" id="pdfToolAddToLegend">+ Add to Legend</button>
        `;
        statusEl.appendChild(addBtns);

        document.getElementById('pdfToolAddToPlans')?.addEventListener('click', () => {
          state.planFiles = [...state.planFiles, fileObj];
          spToast(`Added "${outputName}" to Floor Plans`, 'success');
          addBtns.innerHTML = '<div style="color:#065f46;font-weight:600;padding:4px 0;">✓ Added to Floor Plans</div>';
        });
        document.getElementById('pdfToolAddToSpecs')?.addEventListener('click', () => {
          state.specFiles = [...state.specFiles, fileObj];
          spToast(`Added "${outputName}" to Specifications`, 'success');
          addBtns.innerHTML = '<div style="color:#065f46;font-weight:600;padding:4px 0;">✓ Added to Specifications</div>';
        });
        document.getElementById('pdfToolAddToLegend')?.addEventListener('click', () => {
          state.legendFiles = [...state.legendFiles, fileObj];
          spToast(`Added "${outputName}" to Symbol Legend`, 'success');
          addBtns.innerHTML = '<div style="color:#065f46;font-weight:600;padding:4px 0;">✓ Added to Symbol Legend</div>';
        });
      }
    } catch (err) {
      showStatus('Extraction failed: ' + err.message, true);
      extractBtn.textContent = 'Extract & Download';
      extractBtn.disabled = false;
    }
  });

  function showStatus(msg, isError) {
    const el = document.getElementById('pdfToolStatus');
    if (el) el.innerHTML = `<div class="pdf-tool-status ${isError ? 'error' : ''}">${msg}</div>`;
  }
}

document.addEventListener("DOMContentLoaded", async () => {
  try {
  // Initialize app token if not already set
  if (!sessionStorage.getItem('sp_app_token')) {
    sessionStorage.setItem('sp_app_token', crypto.randomUUID());
  }
  _appToken = sessionStorage.getItem('sp_app_token');

  // Check for existing session before rendering app
  const hasSession = await Auth.init();

  if (hasSession) {
    // User is logged in — load salespeople from server before rendering
    await _loadSalespeopleFromServer();
    // Sync any localStorage-only salespeople to the server
    // This runs on EVERY login (not just one-time) to catch any failed saves
    try {
      const localList = JSON.parse(localStorage.getItem('sp_salespeople') || '[]');
      const needsSync = localStorage.getItem('sp_salespeople_needs_sync') === '1';
      if (localList.length > 0 && (needsSync || !localStorage.getItem('sp_salespeople_migrated'))) {
        let synced = 0;
        for (const sp of localList) {
          const alreadyOnServer = _salespeopleCache.some(s => s.email.toLowerCase() === (sp.email || '').toLowerCase());
          if (!alreadyOnServer && sp.firstName && sp.lastName && sp.email) {
            const ok = await _saveSalespersonToServer(sp);
            if (ok) synced++;
          }
        }
        localStorage.setItem('sp_salespeople_migrated', '1');
        localStorage.removeItem('sp_salespeople_needs_sync');
        if (synced > 0) {
          console.log(`[Salesperson] Synced ${synced} salespeople to server`);
          await _loadSalespeopleFromServer(); // Refresh cache after sync
        }
      }
    } catch (e) { console.warn('[Salesperson] Sync skipped:', e.message); }
    // Start the app
    Auth._updateHeader();
    render();
    QuotaMonitor.start();
    UsageStats.start();
    SecurityDashboard.init();
  } else {
    // No valid session — show login screen
    Auth.showLoginScreen();
  }

  // Online/offline detection — only attach once
  if (!window._spListenersAttached) {
    window._spListenersAttached = true;
    window.addEventListener('offline', () => {
      spToast('You are offline. Changes will not be saved.', 'error');
      document.body.classList.add('is-offline');
    });
    window.addEventListener('online', () => {
      spToast('Back online!', 'success');
      document.body.classList.remove('is-offline');
    });

    // Global event delegation for data-action buttons (replaces inline onclick handlers)
    document.addEventListener('click', (e) => {
      const btn = e.target.closest('[data-action]');
      if (!btn) return;
      const action = btn.getAttribute('data-action');
      switch (action) {
        case 'dismiss-quota-banner':
          QuotaMonitor.dismissBanner();
          break;
        case 'recheck-quota':
          QuotaMonitor.check();
          break;
        case 'auth-logout':
          Auth.logout();
          break;
        case 'close-security-dash':
          SecurityDashboard.close();
          break;
        case 'retry-render':
          render();
          break;
        case 'reload-estimate':
          // v5.127.0: error boundary recovery — reload the current estimate
          // from D1 and re-render. If state.estimateId is present, we can
          // recover. Otherwise fall back to the saved estimates panel.
          if (state.estimateId && typeof loadEstimate === 'function') {
            try {
              loadEstimate(state.estimateId).catch(err => {
                console.error('[ErrorBoundary] reload-estimate failed:', err);
                if (typeof spToast === 'function') spToast('Could not reload estimate: ' + err.message, 'error');
              });
            } catch (e) {
              console.error('[ErrorBoundary] reload-estimate threw:', e);
              if (typeof spToast === 'function') spToast('Could not reload estimate', 'error');
            }
          } else if (typeof showSavedEstimates === 'function') {
            showSavedEstimates();
          }
          break;
        case 'toggle-next':
          // Toggle visibility of the next sibling element
          { const next = btn.nextElementSibling;
            if (next) next.style.display = next.style.display === 'none' ? 'block' : 'none'; }
          break;
        case 'close-saved-panel':
          closeSavedPanel();
          break;
        case 'close-revision-panel':
          closeRevisionPanel();
          break;
        case 'close-actuals-panel':
          closeActualsPanel();
          break;
        case 'close-panel':
          // Generic: remove closest .saved-panel and its backdrop
          { const panel = btn.closest('.saved-panel');
            if (panel) panel.remove();
            document.querySelector('.saved-panel-backdrop')?.remove(); }
          break;
        case 'close-map-popup':
          // Remove the popup container (closest positioned div)
          { const popup = btn.closest('div[style]');
            if (popup) popup.remove(); }
          break;
        case 'inline-compare':
          compareRevision(btn.getAttribute('data-est-id'), btn.getAttribute('data-rev-id'));
          break;
        case 'inline-restore':
          restoreRevision(
            btn.getAttribute('data-est-id'),
            btn.getAttribute('data-rev-id'),
            parseInt(btn.getAttribute('data-rev-num'), 10)
          );
          break;
        case 'open-pdf-tool':
          openPdfPageTool();
          break;
        case 'start-new-bid':
          startNewBid();
          break;
        case 'start-analysis':
          // Jump to analysis step and begin
          if (!state.analyzing && state.planFiles.length > 0) {
            // BID LOCK: If bid was already analyzed, require human confirmation
            if (state.analysisComplete && state.aiAnalysis) {
              const creator = state._estimateCreatedByName || 'the original estimator';
              if (!confirm(`This bid has already been analyzed by ${creator}.\n\nRe-running analysis will create a new version and overwrite the current results.\n\nAre you sure you want to re-analyze?`)) {
                break;
              }
              console.log(`[BidLock] Re-analysis authorized by user (${_currentUser?.name || 'unknown'})`);
            }
            state.currentStep = 5;
            state.completedSteps.add('upload');
            state.completedSteps.add('specs');
            state.completedSteps.add('addenda');
            state.completedSteps.add('travel');
            state.analyzing = true;
            AnalysisTimer.start();
            render();
          } else if (state.planFiles.length === 0) {
            spToast('Upload plan files first before starting analysis', 'warning');
          }
          break;
        case 'stop-analysis':
          if (state.analyzing) {
            window._analysisAborted = true;
            state.analyzing = false;
            AnalysisTimer.stop();
            state.analysisComplete = false;
            state.aiError = 'Analysis stopped by user';
            spToast('Analysis stopped', 'warning');
            // Update buttons
            const stopBtn = document.getElementById('btn-stop-analysis');
            const startBtn = document.getElementById('btn-start-analysis');
            if (stopBtn) stopBtn.style.display = 'none';
            if (startBtn) startBtn.style.display = '';
            render();
          }
          break;
        case 'show-saved-estimates':
          showSavedEstimates();
          break;
        case 'open-company-profile':
          openCompanyProfileEditor();
          break;
        case 'fix-missing-sheets':
          fixMissingSheets();
          break;
        case 'remove-zero-disciplines':
          removeZeroDisciplines();
          break;
      }
    });

    // Unsaved changes warning — prevent accidental navigation loss
    window.addEventListener('beforeunload', (e) => {
      const hasWork = state.projectName.trim() ||
        state.planFiles.length > 0 ||
        state.legendFiles.length > 0 ||
        state.analyzing;
      if (hasWork && !state.analysisComplete) {
        e.preventDefault();
        e.returnValue = '';
      }
    });
  }
  } catch (bootErr) {
    console.error('[Boot] Fatal initialization error:', bootErr);
    document.body.innerHTML = `<div style="padding:40px;text-align:center;font-family:sans-serif;color:#ef4444;">
      <h2>SmartPlans failed to start</h2>
      <p>${bootErr.message || 'Unknown error'}</p>
      <button onclick="location.reload()" style="margin-top:16px;padding:8px 24px;cursor:pointer;">Reload</button>
    </div>`;
  }
});
